import type { DataTableInstance } from "../../core/types"
import { getColumnLabel } from "../../helpers/column-label"
import {
  headerControlsOptionsFromTable,
  shouldShowColumnActions,
  shouldShowColumnFilterButton,
} from "../../helpers/header-controls"
import { ColumnDragHandle } from "../body/dnd"
import { DataTableColumnActions } from "../menus/data-table-column-actions"
import { DataTableColumnFilter } from "./data-table-column-filter"

interface DataTableColumnHeaderProps<TData extends RowData, TValue> {
  header: Header<TData, TValue>
  table: DataTableInstance<TData>
}

const ALIGN_CLASS = {
  left: "justify-start text-left",
  center: "justify-center text-center",
  right: "justify-end text-right",
} as const

/**
 * Wraps every header cell with the MRT layout: label (sort trigger) · sort
 * indicator · multi-sort order badge · column-actions menu, left-aligned by
 * default. Clicking the label cycles asc → desc → none; shift-click multi-sorts
 * (both via TanStack's `getToggleSortingHandler`).
 */
export function DataTableColumnHeader<TData extends RowData, TValue>({
  header,
  table,
}: DataTableColumnHeaderProps<TData, TValue>) {
  const { column } = header
  const { localization, icons } = table.tableInstance
  const controls = headerControlsOptionsFromTable(table)
  const align = column.columnDef.meta?.align ?? "left"

  const showFilterPopover = shouldShowColumnFilterButton(column, controls)
  const hasFilter = column.getFilterValue() != null
  const filterPopover = showFilterPopover ? (
    <Popover>
      <Tooltip>
        <TooltipTrigger asChild>
          <PopoverTrigger asChild>
            <Button
              variant="ghost"
              size="icon"
              aria-label={localization.filterByColumn(getColumnLabel(column))}
              className={cn(
                "size-7 shrink-0 opacity-70 transition-opacity group-hover/th:opacity-100 focus-visible:opacity-100 data-[state=open]:opacity-100",
                hasFilter && "text-primary opacity-100"
              )}
            >
              {hasFilter ? <icons.filter /> : <icons.filterOff />}
            </Button>
          </PopoverTrigger>
        </TooltipTrigger>
        <TooltipContent>
          {localization.filterByColumn(getColumnLabel(column))}
        </TooltipContent>
      </Tooltip>
      <PopoverContent align="start" className="w-64 gap-2">
        <span className="text-xs font-semibold tracking-wide text-muted-foreground uppercase">
          {localization.filterByColumn(getColumnLabel(column))}
        </span>
        <DataTableColumnFilter header={header} table={table} />
      </PopoverContent>
    </Popover>
  ) : null

  const labelNode = header.isPlaceholder
    ? null
    : flexRender(column.columnDef.header, header.getContext())

  const canSort = column.getCanSort()
  const sorted = column.getIsSorted() // false | "asc" | "desc"
  const sortIndex = column.getSortIndex()
  const isMultiSort = table.getState().sorting.length > 1 && sortIndex >= 0

  const showActions = shouldShowColumnActions(column, controls)

  const dragHandle = (
    <ColumnDragHandle
      label={localization.reorderColumn}
      Icon={icons.dragHandle}
    />
  )

  // Non-interactive header (e.g. the selection column): render content plainly.
  if (!canSort && !showActions) {
    return (
      <div
        className={cn("group/th flex items-center gap-1", ALIGN_CLASS[align])}
      >
        {labelNode}
        {dragHandle}
        {filterPopover}
      </div>
    )
  }

  const sortTooltip = !sorted
    ? localization.sortByColumnAsc(getColumnLabel(column))
    : sorted === "asc"
      ? localization.sortByColumnDesc(getColumnLabel(column))
      : localization.clearSort

  return (
    <div
      className={cn(
        "group/th flex items-center gap-0.5",
        align === "right" && "flex-row-reverse",
        ALIGN_CLASS[align]
      )}
    >
      {canSort ? (
        <Tooltip>
          <TooltipTrigger asChild>
            <button
              type="button"
              onClick={column.getToggleSortingHandler()}
              aria-label={sortTooltip}
              className="-mx-1.5 flex min-w-0 items-center gap-1 rounded-sm px-1.5 py-1 text-xs font-medium tracking-wider text-muted-foreground uppercase transition-colors outline-none hover:text-foreground focus-visible:ring-2 focus-visible:ring-ring/40 data-[sorted=true]:text-foreground"
              data-sorted={!!sorted}
            >
              <span className="min-w-0 truncate">{labelNode}</span>
              <SortIndicator sorted={sorted} icons={icons} />
              {isMultiSort && (
                <Badge
                  variant="secondary"
                  className="ml-0.5 h-4 min-w-4 shrink-0 justify-center rounded-sm px-1 text-[10px] leading-none tabular-nums"
                >
                  {sortIndex + 1}
                </Badge>
              )}
            </button>
          </TooltipTrigger>
          <TooltipContent>{sortTooltip}</TooltipContent>
        </Tooltip>
      ) : (
        <span className="min-w-0 truncate px-0 text-xs font-medium tracking-wider uppercase">
          {labelNode}
        </span>
      )}

      {dragHandle}
      {showActions && (
        <DataTableColumnActions
          column={column}
          table={table}
          className="-my-1"
        />
      )}
      {filterPopover}
    </div>
  )
}

function SortIndicator({
  sorted,
  icons,
}: {
  sorted: false | "asc" | "desc"
  icons: DataTableInstance["tableInstance"]["icons"]
}) {
  if (sorted === "asc")
    return <icons.sortAscending className="size-3.5 shrink-0" />
  if (sorted === "desc")
    return <icons.sortDescending className="size-3.5 shrink-0" />
  return (
    <icons.sortUnsorted className="size-3.5 shrink-0 opacity-50 transition-opacity group-hover/th:opacity-70" />
  )
}

"use client"

import {
  SortableContext,
  horizontalListSortingStrategy,
} from "@dnd-kit/sortable"
import type { Header, RowData } from "@tanstack/react-table"
import type { VirtualItem } from "@tanstack/react-virtual"
import * as React from "react"

import {
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import { cn } from "@/lib/utils"

import { DENSITY_CELL_PADDING } from "../../core/constants"
import type { DataTableInstance } from "../../core/types"
import {
  headerControlsOptionsFromTable,
  shouldShowColumnDragGrip,
} from "../../helpers/header-controls"
import type { WithColumnSpacers } from "../../hooks/use-table-virtualizers"
import {
  getColumnPinningClass,
  getColumnPinningStyle,
  getWidthStyle,
} from "../../utils/column-styles"
import { DataTableHeadCell } from "../body/dnd"
import { DataTableColumnFilter } from "./data-table-column-filter"
import { DataTableColumnHeader } from "./data-table-column-header"

interface DataTableHeaderProps<TData extends RowData> {
  table: DataTableInstance<TData>
  virtualColumns: VirtualItem[]
  withColumnSpacers: WithColumnSpacers
}

/**
 * The table `<thead>`: the (optionally sticky) header-group rows and, when
 * enabled, the per-column filter subheader row. Honors column virtualization,
 * ordering (drag handles), pinning, and resizing.
 */
export function DataTableHeader<TData extends RowData>({
  table,
  virtualColumns,
  withColumnSpacers,
}: DataTableHeaderProps<TData>) {
  const {
    density,
    enableColumnResizing,
    enableColumnVirtualization,
    enableColumnFilters,
    showColumnFilters,
    columnFilterDisplayMode,
    enableStickyHeader,
    refs,
  } = table.tableInstance

  const controls = headerControlsOptionsFromTable(table)
  const padding = DENSITY_CELL_PADDING[density]
  const leafColumnIds = table.getVisibleLeafColumns().map((c) => c.id)

  const anyFilterable = table
    .getAllColumns()
    .some((column) => column.getCanFilter())
  const filterRowVisible =
    enableColumnFilters &&
    showColumnFilters &&
    anyFilterable &&
    columnFilterDisplayMode === "subheader"

  const renderHeadCell = (header: Header<TData, unknown>) => (
    <DataTableHeadCell
      key={header.id}
      header={header}
      table={table}
      // Draggable for reordering (column ordering) or to drag onto the group
      // zone (grouping) — the drag-end handler routes by the drop target. The
      // grip's presence drives the column's reserved width, so both read the
      // same predicate (see helpers/header-controls).
      draggable={shouldShowColumnDragGrip(header.column, controls)}
      resizable={enableColumnResizing}
      widthStyle={getWidthStyle(header.column, table)}
      padding={padding}
    >
      {header.isPlaceholder ? null : (
        <DataTableColumnHeader header={header} table={table} />
      )}
    </DataTableHeadCell>
  )

  const renderFilterCell = (header: Header<TData, unknown>) => (
    <TableHead
      key={header.id}
      colSpan={header.colSpan}
      style={{
        ...getWidthStyle(header.column, table),
        ...getColumnPinningStyle(header.column),
      }}
      className={cn(
        "bg-background",
        getColumnPinningClass(header.column)
      )}
    >
      <DataTableColumnFilter header={header} table={table} />
    </TableHead>
  )

  return (
    <TableHeader
      ref={refs.tableHeadRef}
      className={cn(enableStickyHeader && "sticky top-0 z-20 bg-background")}
    >
      {table.getHeaderGroups().map((headerGroup) => (
        <TableRow
          key={headerGroup.id}
          className="group/th hover:bg-transparent"
        >
          {enableColumnVirtualization ? (
            withColumnSpacers(
              virtualColumns
                .map((vc) => {
                  const header = headerGroup.headers[vc.index]
                  return header ? renderHeadCell(header) : null
                })
                .filter(Boolean) as React.ReactNode[],
              `head-${headerGroup.id}`
            )
          ) : (
            <SortableContext
              items={leafColumnIds}
              strategy={horizontalListSortingStrategy}
            >
              {headerGroup.headers.map(renderHeadCell)}
            </SortableContext>
          )}
        </TableRow>
      ))}

      {filterRowVisible &&
        table.getHeaderGroups().map((headerGroup) => (
          <TableRow
            key={`${headerGroup.id}-filters`}
            className="hover:bg-transparent"
          >
            {enableColumnVirtualization
              ? withColumnSpacers(
                  virtualColumns
                    .map((vc) => {
                      const header = headerGroup.headers[vc.index]
                      return header ? renderFilterCell(header) : null
                    })
                    .filter(Boolean) as React.ReactNode[],
                  `filter-${headerGroup.id}`
                )
              : headerGroup.headers.map(renderFilterCell)}
          </TableRow>
        ))}
    </TableHeader>
  )
}

