"use client"

import * as React from "react"
import type { Column, RowData } from "@tanstack/react-table"

import { Input } from "@/components/ui/input"
import { cn } from "@/lib/utils"

import type { IconComponent } from "../../../core/icons"
import type {
  DataTableFilterOption,
  DataTableInstance,
} from "../../../core/types"

export interface FilterFieldProps<TData extends RowData, TValue> {
  column: Column<TData, TValue>
  table: DataTableInstance<TData>
}

export const FIELD_CLASS =
  "h-8 rounded-sm text-xs font-normal tracking-normal normal-case"

export const BETWEEN_MODES = new Set(["between", "betweenInclusive"])

/**
 * Shared Calendar props so the month/year dropdowns are usable regardless of
 * which base Calendar component the consumer ships. The year dropdown derives
 * its options from the startMonth/endMonth range.
 */
export const CALENDAR_NAV_PROPS = {
  captionLayout: "dropdown",
  startMonth: new Date(new Date().getFullYear() - 100, 0),
  endMonth: new Date(new Date().getFullYear() + 10, 11),
} as const

/** A muted pill shown for valueless modes (empty / not empty). */
export function ValuelessLabel({ label }: { label: string }) {
  return (
    <div className="flex h-8 items-center rounded-sm border border-dashed px-2 text-xs text-muted-foreground">
      {label}
    </div>
  )
}

/** Options for select-style variants: explicit `meta.options` or faceted values. */
export function useSelectOptions<TData extends RowData, TValue>(
  column: Column<TData, TValue>
): { options: DataTableFilterOption[]; counts: Map<string, number> } {
  const facets = column.getFacetedUniqueValues()
  return React.useMemo(() => {
    const counts = new Map<string, number>()
    for (const [value, count] of facets) {
      if (value == null) continue
      counts.set(String(value), count)
    }
    const explicit = column.columnDef.meta?.options
    if (explicit && explicit.length > 0) {
      return { options: explicit, counts }
    }
    const options = Array.from(counts.keys())
      .sort((a, b) => a.localeCompare(b))
      .map((value) => ({ label: value, value }))
    return { options, counts }
  }, [facets, column.columnDef.meta?.options])
}

/** A text input with a trailing clear affordance. */
export function ClearableInput({
  value,
  onChange,
  placeholder,
  ariaLabel,
  clearLabel,
  ClearIcon,
}: {
  value: string
  onChange: (next: string) => void
  placeholder: string
  ariaLabel: string
  clearLabel: string
  ClearIcon: IconComponent
}) {
  return (
    <div className="relative flex-1">
      <Input
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        aria-label={ariaLabel}
        className={cn(FIELD_CLASS, value && "pr-7")}
      />
      {value && (
        <button
          type="button"
          aria-label={clearLabel}
          onClick={() => onChange("")}
          className="absolute inset-y-0 right-1.5 flex items-center text-muted-foreground transition-colors hover:text-foreground"
        >
          <ClearIcon className="size-3.5" />
        </button>
      )}
    </div>
  )
}

"use client"

import type { RowData } from "@tanstack/react-table"

import { VALUELESS_MODES } from "../../../fns/filter-fns"
import { getColumnLabel } from "../../../helpers/column-label"
import { getEffectiveMode } from "../../../helpers/effective-filter-mode"
import { ClearableInput, ValuelessLabel, type FilterFieldProps } from "./shared"

export function TextFilterField<TData extends RowData, TValue>({
  column,
  table,
}: FilterFieldProps<TData, TValue>) {
  const { localization, icons } = table.tableInstance
  const mode = getEffectiveMode(column, table)
  if (VALUELESS_MODES.has(mode)) {
    return <ValuelessLabel label={localization.filterModes[mode] ?? mode} />
  }
  const value = (column.getFilterValue() ?? "") as string
  return (
    <ClearableInput
      value={value}
      onChange={(next) => column.setFilterValue(next || undefined)}
      placeholder={localization.filterPlaceholder(getColumnLabel(column))}
      ariaLabel={localization.filterByColumn(getColumnLabel(column))}
      clearLabel={localization.clearFilter}
      ClearIcon={icons.clear}
    />
  )
}

"use client"

import type { Column, RowData } from "@tanstack/react-table"

import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"
import { cn } from "@/lib/utils"

import type { DataTableInstance } from "../../core/types"
import { getColumnLabel } from "../../helpers/column-label"

interface DataTableColumnActionsProps<TData extends RowData, TValue> {
  column: Column<TData, TValue>
  table: DataTableInstance<TData>
  className?: string
}

/**
 * The MRT-signature per-column menu: a vertical-dots ghost button after the
 * header label that opens sort / hide / filter actions. Items render only when
 * the column supports them, so an ID column with sorting/filtering off shows
 * just the hide controls.
 */
export function DataTableColumnActions<TData extends RowData, TValue>({
  column,
  table,
  className,
}: DataTableColumnActionsProps<TData, TValue>) {
  const {
    localization,
    icons,
    setShowColumnFilters,
    columnFilterDisplayMode,
    enableColumnPinning,
    enableGrouping,
    renderColumnActionsMenuItems,
  } = table.tableInstance
  const canSort = column.getCanSort()
  const canHide = column.getCanHide()
  const canFilter = column.getCanFilter()
  const canPin = enableColumnPinning && column.getCanPin()
  const canGroup = enableGrouping && column.getCanGroup()
  const isGrouped = column.getIsGrouped()
  const sorted = column.getIsSorted()
  const pinned = column.getIsPinned()
  const hasFilter = column.getFilterValue() != null

  return (
    <DropdownMenu>
      <Tooltip>
        <TooltipTrigger asChild>
          <DropdownMenuTrigger asChild>
            <Button
              variant="ghost"
              size="icon"
              aria-label={localization.columnActions}
              className={cn(
                "size-7 shrink-0 opacity-70 transition-opacity group-hover/th:opacity-100 focus-visible:opacity-100 data-[state=open]:opacity-100",
                className
              )}
            >
              <icons.columnActions />
            </Button>
          </DropdownMenuTrigger>
        </TooltipTrigger>
        <TooltipContent>{localization.columnActions}</TooltipContent>
      </Tooltip>
      <DropdownMenuContent align="start" className="w-48">
        {canSort && (
          <>
            <DropdownMenuItem
              onClick={() => column.toggleSorting(false)}
              disabled={sorted === "asc"}
            >
              <icons.sortAscending />
              {localization.sortAscending}
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => column.toggleSorting(true)}
              disabled={sorted === "desc"}
            >
              <icons.sortDescending />
              {localization.sortDescending}
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => column.clearSorting()}
              disabled={!sorted}
            >
              <icons.clearAll />
              {localization.clearSort}
            </DropdownMenuItem>
          </>
        )}

        {canFilter && (
          <>
            {canSort && <DropdownMenuSeparator />}
            {columnFilterDisplayMode === "subheader" && (
              <DropdownMenuItem onClick={() => setShowColumnFilters(true)}>
                <icons.filter />
                {localization.filterByColumn(getColumnLabel(column))}
              </DropdownMenuItem>
            )}
            <DropdownMenuItem
              onClick={() => column.setFilterValue(undefined)}
              disabled={!hasFilter}
            >
              <icons.filterOff />
              {localization.clearFilter}
            </DropdownMenuItem>
          </>
        )}

        {canHide && (
          <>
            {(canSort || canFilter) && <DropdownMenuSeparator />}
            <DropdownMenuItem onClick={() => column.toggleVisibility(false)}>
              <icons.hide />
              {localization.hideColumn}
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => table.toggleAllColumnsVisible(true)}
            >
              <icons.clearAll />
              {localization.showAllColumns}
            </DropdownMenuItem>
          </>
        )}

        {canGroup && (
          <>
            {(canSort || canFilter || canHide) && <DropdownMenuSeparator />}
            <DropdownMenuItem onClick={() => column.toggleGrouping()}>
              <icons.group />
              {isGrouped
                ? localization.ungroupByColumn(getColumnLabel(column))
                : localization.groupByColumn(getColumnLabel(column))}
            </DropdownMenuItem>
          </>
        )}

        {canPin && (
          <>
            {(canSort || canFilter || canHide || canGroup) && (
              <DropdownMenuSeparator />
            )}
            <DropdownMenuItem
              onClick={() => column.pin("left")}
              disabled={pinned === "left"}
            >
              <icons.pin />
              {localization.pinToLeft}
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => column.pin("right")}
              disabled={pinned === "right"}
            >
              <icons.pin />
              {localization.pinToRight}
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => column.pin(false)}
              disabled={!pinned}
            >
              <icons.unpin />
              {localization.unpin}
            </DropdownMenuItem>
          </>
        )}

        {renderColumnActionsMenuItems && (
          <>
            {(canSort || canFilter || canHide || canGroup || canPin) && (
              <DropdownMenuSeparator />
            )}
            {renderColumnActionsMenuItems({
              column: column as Column<TData, unknown>,
              table,
            })}
          </>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

"use client"

import type { Column, RowData } from "@tanstack/react-table"

import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuGroup,
  DropdownMenuLabel,
  DropdownMenuRadioGroup,
  DropdownMenuRadioItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"
import { cn } from "@/lib/utils"

import type { DataTableInstance } from "../../core/types"
import { modeOptionsForVariant, type FilterMode } from "../../fns/filter-fns"
import { getEffectiveMode } from "../../helpers/effective-filter-mode"

/**
 * The `Filter` adornment that opens a mode menu (contains/equals/…; numeric and
 * date variants get their own sets). Swapping the mode changes the column's
 * `filterFn` and resets the stale value. Hidden when the variant has a single
 * fixed mode or modes are disabled.
 */
export function DataTableFilterModeMenu<TData extends RowData, TValue>({
  column,
  table,
}: {
  column: Column<TData, TValue>
  table: DataTableInstance<TData>
}) {
  const {
    localization,
    icons,
    setColumnFilterMode,
    enableColumnFilterModes,
    renderColumnFilterModeMenuItems,
  } = table.tableInstance
  const variant = column.columnDef.meta?.variant ?? "text"
  const perColumn = column.columnDef.meta?.enableColumnFilterModes
  const enabled = perColumn ?? enableColumnFilterModes
  // Restrict (and order) to the column's allowed subset when provided.
  const allowed = column.columnDef.meta?.columnFilterModeOptions
  const variantModes = modeOptionsForVariant(variant)
  const modes = allowed
    ? allowed.filter((mode) => variantModes.includes(mode))
    : variantModes

  if (!enabled || modes.length === 0) return null

  const current = getEffectiveMode(column, table)

  return (
    <DropdownMenu>
      <Tooltip>
        <TooltipTrigger asChild>
          <DropdownMenuTrigger asChild>
            <button
              type="button"
              aria-label={localization.changeFilterMode}
              className={cn(
                "flex size-8 shrink-0 items-center justify-center rounded-sm text-muted-foreground transition-colors outline-none hover:text-foreground focus-visible:ring-2 focus-visible:ring-ring/40 aria-expanded:text-foreground"
              )}
            >
              <icons.filter className="size-3.5" />
            </button>
          </DropdownMenuTrigger>
        </TooltipTrigger>
        <TooltipContent>{localization.filterMode}</TooltipContent>
      </Tooltip>
      <DropdownMenuContent align="start" className="w-52">
        {/* Base UI's GroupLabel requires a Group ancestor; Radix renders the
            group as an inert wrapper. */}
        <DropdownMenuGroup>
          <DropdownMenuLabel>{localization.filterMode}</DropdownMenuLabel>
        </DropdownMenuGroup>
        <DropdownMenuSeparator />
        {renderColumnFilterModeMenuItems ? (
          renderColumnFilterModeMenuItems({
            column: column as Column<TData, unknown>,
            modes,
            currentMode: current,
            onSelect: (mode) => setColumnFilterMode(column.id, mode),
            table,
          })
        ) : (
          <DropdownMenuRadioGroup
            value={current}
            onValueChange={(value) =>
              setColumnFilterMode(column.id, value as FilterMode)
            }
          >
            {modes.map((mode) => (
              <DropdownMenuRadioItem key={mode} value={mode}>
                {localization.filterModes[mode] ?? mode}
              </DropdownMenuRadioItem>
            ))}
          </DropdownMenuRadioGroup>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

"use client"

import type { Column, RowData } from "@tanstack/react-table"
import * as React from "react"

import { Button } from "@/components/ui/button"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"

import type {
  AdvancedFilterGroup,
  AdvancedFilterOperator,
  AdvancedFilterRule,
  DataTableInstance,
  FilterVariant,
} from "../../core/types"
import {
  getOperatorsForVariant,
  isValuelessOperator,
} from "../../fns/advanced-filter"
import { getColumnLabel } from "../../helpers/column-label"

// Monotonic ids for new rules. Panel is client-only, so a module counter is
// stable enough (and avoids crypto/uuid deps).
let ruleSeq = 0
const nextRuleId = () => `cn-adv-rule-${++ruleSeq}`

function columnVariant<TData extends RowData>(
  column: Column<TData, unknown> | undefined
): FilterVariant {
  return column?.columnDef.meta?.variant ?? "text"
}

function valueInputType(variant: FilterVariant): "text" | "number" | "date" {
  if (variant === "range" || variant === "range-slider") return "number"
  if (variant === "date" || variant === "date-range") return "date"
  return "text"
}

type Localization<TData extends RowData> =
  DataTableInstance<TData>["tableInstance"]["localization"]

/**
 * Modal dialog for building compound AND/OR filter rules. Edits accumulate in a
 * local draft and are only committed when "Apply" is clicked — closing or
 * cancelling discards them. The body is mounted only while open, so the draft
 * is freshly seeded from the active filter each time the dialog opens.
 */
export function DataTableFilterPanel<TData extends RowData>({
  table,
}: {
  table: DataTableInstance<TData>
}) {
  const { showAdvancedFilterPanel, setShowAdvancedFilterPanel } =
    table.tableInstance
  return (
    <Dialog
      open={showAdvancedFilterPanel}
      onOpenChange={setShowAdvancedFilterPanel}
    >
      {showAdvancedFilterPanel && <FilterPanelContent table={table} />}
    </Dialog>
  )
}

function FilterPanelContent<TData extends RowData>({
  table,
}: {
  table: DataTableInstance<TData>
}) {
  const {
    localization,
    icons,
    advancedFilter,
    setAdvancedFilter,
    setShowAdvancedFilterPanel,
  } = table.tableInstance

  // Seeded once on mount (the dialog body remounts each open).
  const [draft, setDraft] = React.useState<AdvancedFilterGroup>(advancedFilter)

  const { logic, rules } = draft
  const columns = table.getAllLeafColumns().filter((c) => c.getCanFilter())

  const updateRule = (id: string, patch: Partial<AdvancedFilterRule>) =>
    setDraft((group) => ({
      ...group,
      rules: group.rules.map((r) => (r.id === id ? { ...r, ...patch } : r)),
    }))

  const addRule = () => {
    const column = columns[0]
    if (!column) return
    const operator =
      getOperatorsForVariant(columnVariant(column))[0] ?? "contains"
    setDraft((group) => ({
      ...group,
      rules: [
        ...group.rules,
        { id: nextRuleId(), columnId: column.id, operator, value: undefined },
      ],
    }))
  }

  const removeRule = (id: string) =>
    setDraft((group) => ({
      ...group,
      rules: group.rules.filter((r) => r.id !== id),
    }))

  const clearAll = () => setDraft((group) => ({ ...group, rules: [] }))

  const apply = () => {
    setAdvancedFilter(draft)
    setShowAdvancedFilterPanel(false)
  }

  // Changing the column may invalidate the operator/value, so reconcile both.
  const changeColumn = (rule: AdvancedFilterRule, columnId: string) => {
    const operators = getOperatorsForVariant(
      columnVariant(table.getColumn(columnId))
    )
    const operator = operators.includes(rule.operator)
      ? rule.operator
      : (operators[0] ?? "contains")
    updateRule(rule.id, {
      columnId,
      operator,
      value: undefined,
      value2: undefined,
    })
  }

  const changeOperator = (
    rule: AdvancedFilterRule,
    operator: AdvancedFilterOperator
  ) =>
    updateRule(
      rule.id,
      isValuelessOperator(operator)
        ? { operator, value: undefined, value2: undefined }
        : { operator }
    )

  return (
    <DialogContent className="gap-3 sm:max-w-lg">
      <DialogHeader>
        <DialogTitle>{localization.advancedFilters}</DialogTitle>
        <DialogDescription className="sr-only">
          {localization.advancedFilters}
        </DialogDescription>
      </DialogHeader>

      <div className="flex max-h-[50vh] flex-col gap-2 overflow-y-auto">
        <div className="flex flex-wrap items-center gap-2 text-sm">
          <span className="text-muted-foreground">
            {localization.advancedFiltersMatchLabel}
          </span>
          <Select
            value={logic === "or" ? "any" : "all"}
            onValueChange={(v) =>
              setDraft((group) => ({
                ...group,
                logic: v === "any" ? "or" : "and",
              }))
            }
          >
            <SelectTrigger className="h-8 w-20">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">
                {localization.advancedFiltersMatchAll}
              </SelectItem>
              <SelectItem value="any">
                {localization.advancedFiltersMatchAny}
              </SelectItem>
            </SelectContent>
          </Select>
          <span className="text-muted-foreground">
            {localization.advancedFiltersOf}
          </span>
        </div>

        {rules.length === 0 ? (
          <p className="text-sm text-muted-foreground">
            {localization.advancedFiltersEmpty}
          </p>
        ) : (
          <div className="flex flex-col gap-2">
            {rules.map((rule) => {
              const column = table.getColumn(rule.columnId)
              const variant = columnVariant(column)
              const operators = getOperatorsForVariant(variant)
              return (
                <div
                  key={rule.id}
                  className="flex flex-col gap-2 rounded-md border p-2"
                >
                  <div className="flex items-center gap-2">
                    <Select
                      value={rule.columnId}
                      // Base UI's Select can emit null (cleared value); Radix
                      // never does. Guard so both flavors type-check.
                      onValueChange={(v) => {
                        if (v != null) changeColumn(rule, v)
                      }}
                    >
                      <SelectTrigger className="h-8 flex-1">
                        <SelectValue
                          placeholder={localization.advancedFiltersColumn}
                        />
                      </SelectTrigger>
                      <SelectContent>
                        {columns.map((c) => (
                          <SelectItem key={c.id} value={c.id}>
                            {getColumnLabel(c)}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    <Button
                      variant="ghost"
                      size="icon"
                      className="size-8 shrink-0 text-muted-foreground"
                      aria-label={localization.removeFilterRule}
                      onClick={() => removeRule(rule.id)}
                    >
                      <icons.clear />
                    </Button>
                  </div>
                  <div className="flex items-center gap-2">
                    <Select
                      value={rule.operator}
                      onValueChange={(v) =>
                        changeOperator(rule, v as AdvancedFilterOperator)
                      }
                    >
                      <SelectTrigger className="h-8 w-40 shrink-0">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        {operators.map((op) => (
                          <SelectItem key={op} value={op}>
                            {localization.advancedFilterOperators[op] ?? op}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    <RuleValueInput
                      rule={rule}
                      variant={variant}
                      column={column}
                      localization={localization}
                      onChange={(patch) => updateRule(rule.id, patch)}
                    />
                  </div>
                </div>
              )
            })}
          </div>
        )}

        <Button
          variant="outline"
          size="sm"
          className="self-start"
          onClick={addRule}
          disabled={columns.length === 0}
        >
          {localization.advancedFiltersAddRule}
        </Button>
      </div>

      <DialogFooter className="sm:justify-between">
        <Button
          variant="ghost"
          size="sm"
          onClick={clearAll}
          disabled={rules.length === 0}
        >
          {localization.advancedFiltersClearAll}
        </Button>
        <div className="flex items-center gap-2">
          <Button
            variant="outline"
            size="sm"
            onClick={() => setShowAdvancedFilterPanel(false)}
          >
            {localization.cancel}
          </Button>
          <Button size="sm" onClick={apply}>
            {localization.advancedFiltersApply}
          </Button>
        </div>
      </DialogFooter>
    </DialogContent>
  )
}

function RuleValueInput<TData extends RowData>({
  rule,
  variant,
  column,
  localization,
  onChange,
}: {
  rule: AdvancedFilterRule
  variant: FilterVariant
  column: Column<TData, unknown> | undefined
  localization: Localization<TData>
  onChange: (patch: Partial<AdvancedFilterRule>) => void
}) {
  if (isValuelessOperator(rule.operator)) return null

  const options = column?.columnDef.meta?.options
  if ((variant === "select" || variant === "multi-select") && options?.length) {
    return (
      <Select
        value={(rule.value as string | undefined) ?? ""}
        onValueChange={(v) => onChange({ value: v })}
      >
        <SelectTrigger className="h-8 flex-1">
          <SelectValue placeholder={localization.advancedFiltersValue} />
        </SelectTrigger>
        <SelectContent>
          {options.map((o) => (
            <SelectItem key={o.value} value={o.value}>
              {o.label}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>
    )
  }

  if (variant === "checkbox") {
    return (
      <Select
        value={rule.value === undefined ? "" : String(rule.value)}
        onValueChange={(v) => onChange({ value: v === "true" })}
      >
        <SelectTrigger className="h-8 flex-1">
          <SelectValue placeholder={localization.advancedFiltersValue} />
        </SelectTrigger>
        <SelectContent>
          <SelectItem value="true">True</SelectItem>
          <SelectItem value="false">False</SelectItem>
        </SelectContent>
      </Select>
    )
  }

  const type = valueInputType(variant)
  if (rule.operator === "between") {
    return (
      <div className="flex flex-1 items-center gap-1">
        <Input
          type={type}
          className="h-8"
          value={(rule.value as string | undefined) ?? ""}
          onChange={(e) => onChange({ value: e.target.value })}
          placeholder={localization.min}
        />
        <span className="text-muted-foreground">–</span>
        <Input
          type={type}
          className="h-8"
          value={(rule.value2 as string | undefined) ?? ""}
          onChange={(e) => onChange({ value2: e.target.value })}
          placeholder={localization.max}
        />
      </div>
    )
  }

  return (
    <Input
      type={type}
      className="h-8 flex-1"
      value={(rule.value as string | undefined) ?? ""}
      onChange={(e) => onChange({ value: e.target.value })}
      placeholder={localization.advancedFiltersValue}
    />
  )
}

