"use client"

import { DndContext } from "@dnd-kit/core"
import { type RowData } from "@tanstack/react-table"
import * as React from "react"

import { Table, TableCaption } from "@/components/ui/table"
import { TooltipProvider } from "@/components/ui/tooltip"
import { cn } from "@/lib/utils"

import { DataTableBody } from "../components/body/data-table-body"
import {
  DataTableFooter,
  hasFooter,
} from "../components/body/data-table-footer"
import { DataTableEditModal } from "../components/editing/data-table-edit-modal"
import { DataTableHeader } from "../components/head/data-table-header"
import { DataTableAlertBanner } from "../components/toolbar/data-table-alert-banner"
import { DataTableBottomToolbar } from "../components/toolbar/data-table-bottom-toolbar"
import { DataTableDropToGroupZone } from "../components/toolbar/data-table-grouping"
import { DataTablePagination } from "../components/toolbar/data-table-pagination"
import { DataTableToolbar } from "../components/toolbar/data-table-toolbar"
import { useGridNavigation } from "../hooks/use-grid-navigation"
import { useTableDnd } from "../hooks/use-table-dnd"
import { useTableVirtualizers } from "../hooks/use-table-virtualizers"
import { getColumnSizeVars } from "../utils/column-styles"
import { type DataTableInstance } from "./types"

/**
 * Body wrapper that freezes during an active column resize. With
 * `columnResizeMode: "onChange"` the table re-renders on every mousemove;
 * skipping the body's re-render keeps drags smooth, since column widths come
 * from the CSS size vars on `<table>` and update without React. Outside of a
 * resize the comparator returns false, so normal re-rendering is unchanged.
 */
const MemoizedDataTableBody = React.memo(
  DataTableBody,
  (_prev, next) =>
    next.table.getState().columnSizingInfo.isResizingColumn !== false
) as typeof DataTableBody

interface DataTableProps<
  TData extends RowData,
> extends React.ComponentProps<"div"> {
  table: DataTableInstance<TData>
  /** Page-size options for the bottom pagination control. */
  pageSizeOptions?: number[]
  /** Extra classes for the scrollable table surface (e.g. a max-height to
   *  engage the sticky header/footer or to bound a virtualized list). */
  surfaceClassName?: string
}

/**
 * Renders a data table from an instance produced by {@link useDataTable}.
 * Vertical stack: top toolbar → alert banner → drop-to-group zone → bordered
 * surface (sticky header, optional filter row, body, optional sticky footer) →
 * pagination. Wires DnD column/row ordering, pinning, resizing, grouping,
 * expansion, and detail panels.
 */
export function DataTable<TData extends RowData>({
  table,
  pageSizeOptions,
  surfaceClassName,
  className,
  ...props
}: DataTableProps<TData>) {
  const {
    density,
    isFullscreen,
    showProgressBars,
    showLoadingOverlay,
    enableColumnResizing,
    enableGrouping,
    enableRowVirtualization,
    enablePagination,
    positionPagination,
    positionToolbarAlertBanner,
    positionToolbarDropZone,
    enableTopToolbar,
    enableKeyboardNavigation,
    renderCaption,
    renderTopToolbar,
    refs,
  } = table.tableInstance

  const { ref: gridRef, onKeyDown } = useGridNavigation<HTMLDivElement>(
    enableKeyboardNavigation
  )
  const { sensors, collisionDetection, handleDragEnd } = useTableDnd(table)
  const { rowVirtualizer, virtualItems, virtualColumns, withColumnSpacers } =
    useTableVirtualizers(table, gridRef)

  const hasRows =
    table.getTopRows().length +
      table.getCenterRows().length +
      table.getBottomRows().length >
    0
  const showFooter = hasFooter(table)

  const columnSizing = table.getState().columnSizing
  const columnSizingInfo = table.getState().columnSizingInfo
  const columnSizeVars = React.useMemo(
    () => (enableColumnResizing ? getColumnSizeVars(table) : {}),
    // columnSizing/Info are intentional triggers: recompute vars on resize.
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [enableColumnResizing, table, columnSizing, columnSizingInfo]
  )

  return (
    // Radix names the open delay `delayDuration`; Base UI's provider names it
    // `delay`. Both are context-only components that ignore foreign props, so
    // passing both (via an assertion, since each flavor types only its own)
    // keeps this file flavor-neutral for the registry's install-time transform.
    <TooltipProvider
      {...({
        delayDuration: 300,
        delay: 300,
      } as Partial<React.ComponentProps<typeof TooltipProvider>>)}
    >
      <div
        ref={refs.tablePaperRef}
        data-slot="data-table"
        className={cn(
          "flex w-full flex-col gap-2",
          isFullscreen &&
            "fixed inset-0 z-50 gap-2 overflow-auto bg-background p-4",
          className
        )}
        data-density={density}
        {...props}
      >
        {renderTopToolbar
          ? renderTopToolbar({ table })
          : enableTopToolbar && (
              <DataTableToolbar
                table={table}
                toolbarRef={refs.topToolbarRef}
                searchInputRef={refs.searchInputRef}
              />
            )}
        {positionToolbarAlertBanner === "top" && (
          <DataTableAlertBanner table={table} />
        )}

        {enablePagination &&
          (positionPagination === "top" || positionPagination === "both") && (
            <DataTablePagination
              table={table}
              pageSizeOptions={pageSizeOptions}
            />
          )}

        <DndContext
          sensors={sensors}
          collisionDetection={collisionDetection}
          onDragEnd={handleDragEnd}
        >
          {enableGrouping &&
            (positionToolbarDropZone === "top" ||
              positionToolbarDropZone === "both") && (
              <DataTableDropToGroupZone table={table} />
            )}

          <div
            ref={(node) => {
              gridRef.current = node
              refs.tableContainerRef.current = node
            }}
            onKeyDown={onKeyDown}
            data-slot="data-table-surface"
            className={cn(
              // This surface is the single scroll container for both axes, so
              // the sticky header/footer engage and the horizontal scrollbar
              // stays pinned to the visible bottom. Neutralize the shadcn
              // <Table> wrapper's own overflow so it doesn't become a second
              // (unbounded) scroll container that breaks sticky positioning.
              "relative overflow-auto rounded-md border *:data-[slot=table-container]:overflow-visible",
              enableRowVirtualization && "max-h-150",
              surfaceClassName
            )}
          >
            {showProgressBars && (
              <div
                data-slot="data-table-progress"
                className="absolute inset-x-0 top-0 z-30 h-0.5 overflow-hidden bg-primary/20"
                role="presentation"
              >
                {/* @keyframes can't go in an inline style attribute, so the rule
                    lives in this co-located <style> — keeping the table
                    self-contained (no globals.css / registry CSS needed). The
                    animation itself is applied inline; reduced motion stops it. */}
                <style>
                  {
                    "@keyframes data-table-progress{from{transform:translateX(-100%)}to{transform:translateX(400%)}}@media (prefers-reduced-motion:reduce){[data-slot=data-table-progress-bar]{animation:none!important}}"
                  }
                </style>
                <div
                  data-slot="data-table-progress-bar"
                  className="h-full w-1/3 bg-primary"
                  style={{
                    animation: "data-table-progress 1.1s ease-in-out infinite",
                  }}
                />
              </div>
            )}

            <Table
              style={{
                ...columnSizeVars,
                // Fixed layout makes per-column widths authoritative (auto
                // layout would stretch/redistribute them and ignore a resize).
                // `max(100%, totalSize)` keeps the table at least as wide as the
                // surface: when the columns are narrower than the surface, fixed
                // layout distributes the slack proportionally so they fill it
                // (no trailing empty space); when they outgrow the surface, the
                // table exceeds 100% and scrolls horizontally.
                ...(enableColumnResizing
                  ? { width: `max(100%, ${table.getTotalSize()}px)` }
                  : null),
              }}
              className={cn(enableColumnResizing && "table-fixed")}
            >
              {renderCaption && (
                <TableCaption>{renderCaption({ table })}</TableCaption>
              )}
              <DataTableHeader
                table={table}
                virtualColumns={virtualColumns}
                withColumnSpacers={withColumnSpacers}
              />
              <MemoizedDataTableBody
                table={table}
                rowVirtualizer={rowVirtualizer}
                virtualItems={virtualItems}
                virtualColumns={virtualColumns}
                withColumnSpacers={withColumnSpacers}
              />
              {showFooter && (
                <DataTableFooter
                  table={table}
                  virtualColumns={virtualColumns}
                  withColumnSpacers={withColumnSpacers}
                />
              )}
            </Table>

            {showLoadingOverlay && hasRows && (
              <div
                className="absolute inset-0 z-10 bg-background/40"
                aria-hidden
              />
            )}
          </div>

          {enableGrouping &&
            (positionToolbarDropZone === "bottom" ||
              positionToolbarDropZone === "both") && (
              <DataTableDropToGroupZone table={table} />
            )}
        </DndContext>

        {positionToolbarAlertBanner === "bottom" && (
          <DataTableAlertBanner table={table} />
        )}

        <DataTableBottomToolbar
          table={table}
          pageSizeOptions={pageSizeOptions}
        />

        <DataTableEditModal table={table} />
      </div>
    </TooltipProvider>
  )
}

import type {
  Cell,
  Column,
  Row,
  RowData,
  Table,
  TableOptions,
} from "@tanstack/react-table"
import type * as React from "react"

import type { Virtualizer, VirtualizerOptions } from "@tanstack/react-virtual"

import type { FilterMode, GlobalFilterMode } from "../fns/filter-fns"
import type { DataTableIcons } from "./icons"
import type { DataTableLocalization } from "./localization"

// Re-exported as part of the public type surface: these describe column-`meta`
// filter config, while the runtime filter fns stay internal.
export type { FilterMode, GlobalFilterMode } from "../fns/filter-fns"

export type Density = "compact" | "comfortable" | "spacious"

/** The `@tanstack/react-virtual` instance powering body-row virtualization. */
export type DataTableRowVirtualizer = Virtualizer<
  HTMLDivElement,
  HTMLTableRowElement
>
/** The `@tanstack/react-virtual` instance powering column virtualization. */
export type DataTableColumnVirtualizer = Virtualizer<
  HTMLDivElement,
  HTMLTableCellElement
>

/** A value, or a function of the table instance returning that value. */
type ValueOrFunc<TData extends RowData, TValue> =
  | TValue
  | ((props: { table: DataTableInstance<TData> }) => TValue)

/** Partial passthrough merged into the row `useVirtualizer` call. */
export type RowVirtualizerOptions<TData extends RowData> = ValueOrFunc<
  TData,
  Partial<VirtualizerOptions<HTMLDivElement, HTMLTableRowElement>>
>
/** Partial passthrough merged into the column `useVirtualizer` call. */
export type ColumnVirtualizerOptions<TData extends RowData> = ValueOrFunc<
  TData,
  Partial<VirtualizerOptions<HTMLDivElement, HTMLTableCellElement>>
>

/**
 * DOM refs to the table's structural elements, exposed on
 * `table.tableInstance.refs` for imperative access (focus, measure, scroll). Each is
 * populated after mount and may be `null` when its element isn't rendered
 * (e.g. `bottomToolbarRef` with no bottom toolbar, `tableFooterRef` with no
 * footer, `searchInputRef` before the search box is expanded).
 */
export interface DataTableRefs {
  /** The outermost `data-slot="data-table"` wrapper. Always present. */
  tablePaperRef: React.RefObject<HTMLDivElement | null>
  /** The scroll container (`data-slot="data-table-surface"`) — the single
   *  scroll container for both axes. Always present. */
  tableContainerRef: React.RefObject<HTMLDivElement | null>
  /** The top toolbar root (`data-slot="data-table-toolbar"`). `null` when the
   *  top toolbar is disabled or replaced via `renderTopToolbar`. */
  topToolbarRef: React.RefObject<HTMLDivElement | null>
  /** The bottom toolbar root (`data-slot="data-table-bottom-toolbar"`). `null`
   *  when there is no bottom toolbar, or it is replaced via
   *  `renderBottomToolbar`. */
  bottomToolbarRef: React.RefObject<HTMLDivElement | null>
  /** The `<thead>` element. Always present. */
  tableHeadRef: React.RefObject<HTMLTableSectionElement | null>
  /** The `<tfoot>` element. `null` unless a column defines a `footer`. */
  tableFooterRef: React.RefObject<HTMLTableSectionElement | null>
  /** The global-search `<input>`. `null` until the search box is expanded. */
  searchInputRef: React.RefObject<HTMLInputElement | null>
}

/** Filter UI variants (full set wired in Phase 2; Phase 1 ships "text"). */
export type FilterVariant =
  | "text"
  | "select"
  | "multi-select"
  | "checkbox"
  | "range"
  | "range-slider"
  | "date"
  | "date-range"

export interface DataTableFilterOption {
  label: string
  value: string
}

/** Operators for the advanced filter panel's compound rules. Availability per
 *  column is gated by its `meta.variant` (see `getOperatorsForVariant`). */
export type AdvancedFilterOperator =
  | "isEmpty"
  | "isNotEmpty"
  | "equals"
  | "notEquals"
  | "contains"
  | "notContains"
  | "startsWith"
  | "endsWith"
  | "greaterThan"
  | "greaterThanOrEqual"
  | "lessThan"
  | "lessThanOrEqual"
  | "between"

/** A single advanced-filter condition: column + operator + value(s). */
export interface AdvancedFilterRule {
  /** Stable key for React + edits. */
  id: string
  columnId: string
  operator: AdvancedFilterOperator
  /** Comparison value (string / number / Date / undefined). */
  value: unknown
  /** Upper bound, only used by the `between` operator. */
  value2?: unknown
}

/** The full advanced filter: a flat list of rules joined by one logic mode. */
export interface AdvancedFilterGroup {
  logic: "and" | "or"
  rules: AdvancedFilterRule[]
}

export type EditDisplayMode = "cell" | "row" | "table" | "modal" | "custom"

/** How the create form is surfaced (decoupled from {@link EditDisplayMode}). */
export type CreateDisplayMode = "modal" | "row" | "custom"

/** How the pagination controls render. `"pages"` = numbered page buttons. */
export type PaginationDisplayMode = "default" | "pages" | "custom"

/** Where column filter inputs live: the filter subheader row or per-column
 *  popovers opened from the column header. */
export type ColumnFilterDisplayMode = "subheader" | "popover" | "custom"

/** Which cell is being edited (cell mode). */
export interface EditingCell {
  rowId: string
  columnId: string
}

/** Edit-field variants for the inline editors. */
export type EditVariant = "text" | "number" | "select"

// Per-column configuration carried on `columnDef.meta`. Augments the TanStack
// `ColumnMeta` interface so it is strongly typed everywhere `meta` is read.
declare module "@tanstack/react-table" {
  interface ColumnMeta<TData extends RowData, TValue> {
    /** Filter UI variant rendered in the filter row. Defaults to "text". */
    variant?: FilterVariant
    /** Options for `select` / `multi-select` filter variants. If omitted for a
     *  select-style variant, options are derived from faceted unique values. */
    options?: DataTableFilterOption[]
    /** Default filter mode for this column (overrides the per-variant default). */
    filterMode?: FilterMode
    /** Per-column override for the filter-mode menu (defaults to the table). */
    enableColumnFilterModes?: boolean
    /** Custom filter UI for this column (escape hatch). Replaces the variant. */
    renderColumnFilter?: (props: {
      column: Column<TData, TValue>
      table: DataTableInstance<TData>
    }) => React.ReactNode
    /** Restrict (and order) the filter-mode menu for this column to this subset
     *  of modes. Include the column's default mode. */
    columnFilterModeOptions?: FilterMode[]
    /** Allow editing this column (defaults to true when table editing is on). */
    enableEditing?: boolean
    /** Inline editor variant. Defaults to "text". */
    editVariant?: EditVariant
    /** Options for the "select" edit variant. */
    editSelectOptions?: DataTableFilterOption[]
    /** Custom inline editor for this column (escape hatch). Replaces the built-in
     *  editor while the cell/row is editing; drive the value via `table.tableInstance`
     *  (`rowDraft`/`setRowDraftValue` or `onEditCellSave`). */
    renderEditCell?: (props: CellRenderProps<TData, TValue>) => React.ReactNode
    /** Custom render for this column's group header cell (when grouped). */
    renderGroupedCell?: (
      props: CellRenderProps<TData, TValue>
    ) => React.ReactNode
    /** Custom render for this column's aggregated cell (when grouped). Overrides
     *  the TanStack `columnDef.aggregatedCell`. */
    renderAggregatedCell?: (
      props: CellRenderProps<TData, TValue>
    ) => React.ReactNode
    /** Custom render for this column's placeholder cells in grouped rows (cells
     *  with no value because another column owns the group). Default: empty. */
    renderPlaceholderCell?: (
      props: CellRenderProps<TData, TValue>
    ) => React.ReactNode
    /** Validate an edited value; return an error message or undefined if valid. */
    validate?: (value: unknown) => string | undefined
    /** Show a click-to-copy affordance on this column's cells. */
    enableClickToCopy?: boolean
    /** Horizontal alignment applied to the header label and body cells. */
    align?: "left" | "center" | "right"
    /** Opt this column out of match highlighting. */
    disableHighlight?: boolean
    /** Hide the column-actions menu for this column. */
    disableColumnActions?: boolean
    /** Human-readable label for menus when the header is not a plain string. */
    label?: string
  }
}

export interface DataTableSlotProps<TData extends RowData> {
  table: DataTableInstance<TData>
}

export interface RowEvent<TData extends RowData> {
  row: Row<TData>
  table: DataTableInstance<TData>
  event: React.MouseEvent<HTMLTableRowElement>
}

export interface CellEvent<TData extends RowData> {
  cell: Cell<TData, unknown>
  row: Row<TData>
  table: DataTableInstance<TData>
  event: React.MouseEvent<HTMLTableCellElement>
}

/** Props passed to per-column cell render hooks on `columnDef.meta`. */
export interface CellRenderProps<TData extends RowData, TValue = unknown> {
  cell: Cell<TData, TValue>
  row: Row<TData>
  column: Column<TData, TValue>
  table: DataTableInstance<TData>
}

/**
 * Our configuration + UI state, attached to the TanStack table instance under
 * `table.tableInstance`. Sub-components read it from the instance rather than via
 * prop drilling (mirrors Material React Table's `table.options` pattern).
 */
export interface DataTableConfig<TData extends RowData> {
  localization: DataTableLocalization
  icons: DataTableIcons
  density: Density
  setDensity: React.Dispatch<React.SetStateAction<Density>>
  isFullscreen: boolean
  setIsFullscreen: React.Dispatch<React.SetStateAction<boolean>>
  showColumnFilters: boolean
  setShowColumnFilters: React.Dispatch<React.SetStateAction<boolean>>
  /** Active filter mode per column id. */
  columnFilterModes: Record<string, FilterMode>
  /** Switch a column's filter mode (resets the value when it becomes invalid). */
  setColumnFilterMode: (columnId: string, mode: FilterMode) => void
  globalFilterMode: GlobalFilterMode
  setGlobalFilterMode: (mode: GlobalFilterMode) => void
  enableGlobalFilter: boolean
  enableGlobalFilterModes: boolean
  /** Compound AND/OR filter panel (independent of, and additive to, the
   *  per-column filters and global search). */
  enableAdvancedFilter: boolean
  advancedFilter: AdvancedFilterGroup
  setAdvancedFilter: React.Dispatch<React.SetStateAction<AdvancedFilterGroup>>
  showAdvancedFilterPanel: boolean
  setShowAdvancedFilterPanel: React.Dispatch<React.SetStateAction<boolean>>
  isLoading: boolean
  isSaving: boolean
  showProgressBars: boolean
  showSkeletons: boolean
  showLoadingOverlay: boolean
  enableFacetedValues: boolean
  enableColumnActions: boolean
  enableColumnFilters: boolean
  enableColumnFilterModes: boolean
  enableFilterMatchHighlighting: boolean
  /** Column ids that supply a custom cell renderer (skipped by auto-highlight). */
  columnsWithCustomCell: ReadonlySet<string>
  enableColumnOrdering: boolean
  enableColumnPinning: boolean
  enableColumnResizing: boolean
  enableColumnAutosize: boolean
  /** Resize a single column to fit its widest visible value (header + data). */
  autoSizeColumn: (columnId: string) => void
  /** Auto-size every resizable visible column. */
  autoSizeAllColumns: () => void
  enableRowOrdering: boolean
  enableRowPinning: boolean
  enableRowNumbers: boolean
  rowNumberMode: "static" | "original"
  /** Called on a row drag-and-drop reorder; the consumer reorders its data. */
  onRowOrderChange?: (activeRowId: string, overRowId: string) => void
  enableGrouping: boolean
  enableExpanding: boolean
  enableStickyFooter: boolean
  renderDetailPanel?: (props: {
    row: Row<TData>
    table: DataTableInstance<TData>
  }) => React.ReactNode

  // Editing / actions
  enableEditing: boolean
  editDisplayMode: EditDisplayMode
  createDisplayMode: CreateDisplayMode
  editingCell: EditingCell | null
  setEditingCell: React.Dispatch<React.SetStateAction<EditingCell | null>>
  editingRowId: string | null
  isCreating: boolean
  /** Draft values for the row/modal editor + create form, keyed by column id. */
  rowDraft: Record<string, unknown>
  setRowDraftValue: (columnId: string, value: unknown) => void
  /** Enter row/modal editing for a row, seeding the draft from its values. */
  beginRowEdit: (row: Row<TData>) => void
  /** Open the create form, seeding the draft from `createRowDefaults`. */
  beginCreate: () => void
  /** Exit any editing/creating state, discarding the draft. */
  cancelEdit: () => void
  enableClickToCopy: boolean
  onEditCellSave?: (props: {
    row: Row<TData>
    column: Column<TData, unknown>
    value: unknown
    table: DataTableInstance<TData>
  }) => void
  onSaveRow?: (props: {
    row: Row<TData>
    values: Record<string, unknown>
    table: DataTableInstance<TData>
    exit: () => void
  }) => void
  onCreateRow?: (props: {
    values: Record<string, unknown>
    table: DataTableInstance<TData>
    exit: () => void
  }) => void
  renderRowActions?: (props: {
    row: Row<TData>
    table: DataTableInstance<TData>
  }) => React.ReactNode
  renderCellActionMenuItems?: (props: {
    cell: Cell<TData, unknown>
    row: Row<TData>
    table: DataTableInstance<TData>
  }) => React.ReactNode
  renderRowActionMenuItems?: (props: {
    row: Row<TData>
    table: DataTableInstance<TData>
  }) => React.ReactNode
  renderColumnActionsMenuItems?: (props: {
    column: Column<TData, unknown>
    table: DataTableInstance<TData>
  }) => React.ReactNode
  renderColumnFilterModeMenuItems?: (props: {
    column: Column<TData, unknown>
    modes: FilterMode[]
    currentMode: FilterMode
    onSelect: (mode: FilterMode) => void
    table: DataTableInstance<TData>
  }) => React.ReactNode
  renderGlobalFilterModeMenuItems?: (props: {
    modes: GlobalFilterMode[]
    currentMode: GlobalFilterMode
    onSelect: (mode: GlobalFilterMode) => void
    table: DataTableInstance<TData>
  }) => React.ReactNode

  // Event listeners
  onRowClick?: (props: RowEvent<TData>) => void
  onRowDoubleClick?: (props: RowEvent<TData>) => void
  onCellClick?: (props: CellEvent<TData>) => void
  onCellDoubleClick?: (props: CellEvent<TData>) => void

  /** DOM refs to the table's structural elements (populated after mount). */
  refs: DataTableRefs
  enableRowVirtualization: boolean
  enableColumnVirtualization: boolean
  estimateRowHeight: number
  virtualOverscan: number
  rowVirtualizerOptions?: RowVirtualizerOptions<TData>
  columnVirtualizerOptions?: ColumnVirtualizerOptions<TData>
  rowVirtualizerInstanceRef?: React.RefObject<DataTableRowVirtualizer | null>
  columnVirtualizerInstanceRef?: React.RefObject<DataTableColumnVirtualizer | null>
  enableExport: boolean
  exportFileName?: string
  enableStickyHeader: boolean
  enablePagination: boolean
  positionPagination: "top" | "bottom" | "both" | "none"
  paginationDisplayMode: PaginationDisplayMode
  columnFilterDisplayMode: ColumnFilterDisplayMode
  positionGlobalFilter: "left" | "right" | "none"
  positionToolbarAlertBanner: "top" | "bottom" | "none"
  positionToolbarDropZone: "top" | "bottom" | "both" | "none"
  enableRowSelection: boolean
  enableTopToolbar: boolean
  enableBottomToolbar: boolean
  enableDensityToggle: boolean
  enableFullscreenToggle: boolean
  enableToolbarInternalActions: boolean
  enableKeyboardNavigation: boolean
  title?: React.ReactNode
  renderToolbarActions?: (props: DataTableSlotProps<TData>) => React.ReactNode
  renderTopToolbar?: (props: DataTableSlotProps<TData>) => React.ReactNode
  renderBottomToolbar?: (props: DataTableSlotProps<TData>) => React.ReactNode
  renderToolbarInternalActions?: (
    props: DataTableSlotProps<TData>
  ) => React.ReactNode
  renderBottomToolbarCustomActions?: (
    props: DataTableSlotProps<TData>
  ) => React.ReactNode
  renderCaption?: (props: DataTableSlotProps<TData>) => React.ReactNode
  renderEmpty?: (props: DataTableSlotProps<TData>) => React.ReactNode
}

/** A TanStack table instance enriched with our `tableInstance` config. */
export type DataTableInstance<TData extends RowData = unknown> =
  Table<TData> & {
    tableInstance: DataTableConfig<TData>
  }

/**
 * Options for {@link useDataTable}. Extends the full TanStack `TableOptions`
 * (so controlled state, `manual*` flags, `getRowId`, etc. all pass through)
 * and adds our presentation/feature options. `getCoreRowModel` and the other
 * row models are supplied with sensible defaults but can be overridden.
 */
export interface UseDataTableOptions<TData extends RowData> extends Omit<
  TableOptions<TData>,
  "getCoreRowModel"
> {
  getCoreRowModel?: TableOptions<TData>["getCoreRowModel"]
  localization?: Partial<DataTableLocalization>
  /** Override any subset of the table's icons. */
  icons?: Partial<DataTableIcons>
  /** Initial density. Uncontrolled. */
  defaultDensity?: Density
  /** Initially show the filter row. Uncontrolled. */
  defaultShowColumnFilters?: boolean
  /** Show the loading affordances (progress bar; skeletons when empty; a dimming
   *  overlay over existing rows). Toggle each independently below. */
  isLoading?: boolean
  /** Show the progress bar for an in-flight save/mutation. Defaults the progress
   *  bar on without replacing rows with skeletons. */
  isSaving?: boolean
  /** Show the top progress bar. Default: `isLoading || isSaving`. */
  showProgressBars?: boolean
  /** Replace the body with skeleton rows while empty. Default: `isLoading`. */
  showSkeletons?: boolean
  /** Dim existing rows with an overlay while loading. Default: `isLoading`. */
  showLoadingOverlay?: boolean
  /** Compute faceted unique values / min-max (auto select options + range
   *  bounds). Default true; disable to skip the faceted row models. */
  enableFacetedValues?: boolean
  enableColumnActions?: boolean
  /** Show the filter-mode menu adornment on filter fields. Default true. */
  enableColumnFilterModes?: boolean
  /** Highlight matched substrings in cells. Default true. */
  enableFilterMatchHighlighting?: boolean
  /** Show the expandable global search in the toolbar. Default true. */
  enableGlobalFilter?: boolean
  /** Show the global search mode menu (fuzzy/contains/…). Default true. */
  enableGlobalFilterModes?: boolean
  /** While the global search is in fuzzy mode, order rows by best match (most
   *  relevant first) until the user applies their own sort. Default false —
   *  MRT defaults this on, but the data table keeps it off so searching never silently
   *  reorders rows unless opted in. Ignored for non-fuzzy modes, when grouping
   *  or expanded, or under manual sorting/filtering. */
  enableGlobalFilterRankedResults?: boolean
  /** Initial global search mode. Default "fuzzy". */
  defaultGlobalFilterMode?: GlobalFilterMode
  /** Controlled density. Pair with `onDensityChange`; omit for uncontrolled
   *  (seed the initial value with `defaultDensity`). */
  density?: Density
  /** Called whenever the density changes (toolbar toggle or programmatic). */
  onDensityChange?: (density: Density) => void
  /** Controlled full-screen state. Pair with `onIsFullscreenChange`. */
  isFullscreen?: boolean
  /** Called whenever the full-screen state is toggled. */
  onIsFullscreenChange?: (isFullscreen: boolean) => void
  /** Controlled filter-row visibility. Pair with `onShowColumnFiltersChange`;
   *  omit for uncontrolled (seed with `defaultShowColumnFilters`). */
  showColumnFilters?: boolean
  /** Called whenever the filter row is shown or hidden. */
  onShowColumnFiltersChange?: (showColumnFilters: boolean) => void
  /** Enable the advanced filter panel: compound rules joined by AND/OR, applied
   *  on top of the per-column filters. A toolbar button opens the panel and
   *  shows the active-rule count. Default false. */
  enableAdvancedFilter?: boolean
  /** Controlled advanced filter. Pair with `onAdvancedFilterChange`; omit for
   *  uncontrolled (seed with `defaultAdvancedFilter`). */
  advancedFilter?: AdvancedFilterGroup
  /** Initial advanced filter for uncontrolled usage. */
  defaultAdvancedFilter?: AdvancedFilterGroup
  /** Called whenever the advanced filter changes. */
  onAdvancedFilterChange?: (filter: AdvancedFilterGroup) => void
  /** Controlled global search mode. Pair with `onGlobalFilterModeChange`;
   *  omit for uncontrolled (seed with `defaultGlobalFilterMode`). */
  globalFilterMode?: GlobalFilterMode
  /** Called whenever the global search mode changes. */
  onGlobalFilterModeChange?: (mode: GlobalFilterMode) => void
  /** Drag-and-drop column reordering (adds a grip to each header). */
  enableColumnOrdering?: boolean
  /** Column pinning (left/right) via the column-actions menu + sticky columns. */
  enableColumnPinning?: boolean
  /** Column resizing via an edge drag handle. */
  enableColumnResizing?: boolean
  /**
   * Double-clicking a column's resize handle auto-sizes it to fit its widest
   * value. Defaults to `enableColumnResizing`. When off, double-click resets
   * the column to its default size instead.
   */
  enableColumnAutosize?: boolean
  /** Drag-and-drop row reordering (adds a drag-handle column). */
  enableRowOrdering?: boolean
  /** Row pinning (top) via a pin toggle in the row-number column. */
  enableRowPinning?: boolean
  /** Adds a leading row-number column. */
  enableRowNumbers?: boolean
  /** "static" tracks the current view (page-aware); "original" uses source index. */
  rowNumberMode?: "static" | "original"
  /** Called on a row drag-and-drop reorder; the consumer reorders its data. */
  onRowOrderChange?: (activeRowId: string, overRowId: string) => void
  /** Row grouping (group-by menu + drop-to-group zone + aggregated group rows). */
  enableGrouping?: boolean
  /** Row expansion (tree sub-rows and/or detail panels). Auto-on with grouping
   *  or when `renderDetailPanel`/`getSubRows` is provided. */
  enableExpanding?: boolean
  /** Pin the footer (aggregation/footer cells) to the bottom of the surface.
   *  Default true (matches the sticky header). */
  enableStickyFooter?: boolean
  /** Render an expanding detail panel for each row. */
  renderDetailPanel?: (props: {
    row: Row<TData>
    table: DataTableInstance<TData>
  }) => React.ReactNode

  // Editing / actions
  /** Enable inline editing. */
  enableEditing?: boolean
  /** How edits are surfaced. Default "cell". */
  editDisplayMode?: EditDisplayMode
  /** How the create form is surfaced, independent of `editDisplayMode`:
   *  `"modal"` (dialog, default), `"row"` (an inline editable row at the top of
   *  the table), or `"custom"` (you render it from `isCreating` + `rowDraft`). */
  createDisplayMode?: CreateDisplayMode
  /** Default values for the create form, keyed by column id. */
  createRowDefaults?: Record<string, unknown>
  /** Show a click-to-copy affordance on all cells (per-column override via meta). */
  enableClickToCopy?: boolean
  onEditCellSave?: (props: {
    row: Row<TData>
    column: Column<TData, unknown>
    value: unknown
    table: DataTableInstance<TData>
  }) => void
  onSaveRow?: (props: {
    row: Row<TData>
    values: Record<string, unknown>
    table: DataTableInstance<TData>
    exit: () => void
  }) => void
  onCreateRow?: (props: {
    values: Record<string, unknown>
    table: DataTableInstance<TData>
    exit: () => void
  }) => void
  renderRowActions?: (props: {
    row: Row<TData>
    table: DataTableInstance<TData>
  }) => React.ReactNode
  renderCellActionMenuItems?: (props: {
    cell: Cell<TData, unknown>
    row: Row<TData>
    table: DataTableInstance<TData>
  }) => React.ReactNode
  /** Render a kebab menu in the row-actions column. Returns the menu items
   *  (e.g. `<DropdownMenuItem>`); injects the actions column automatically. */
  renderRowActionMenuItems?: (props: {
    row: Row<TData>
    table: DataTableInstance<TData>
  }) => React.ReactNode
  /** Append custom items to the bottom of every column-actions menu. Returns the
   *  items (e.g. `<DropdownMenuItem>`); a separator is added before them. */
  renderColumnActionsMenuItems?: (props: {
    column: Column<TData, unknown>
    table: DataTableInstance<TData>
  }) => React.ReactNode
  /** Replace the radio items in a column's filter-mode menu. Render your own
   *  items and call `onSelect(mode)` to switch; `modes` is the allowed set. */
  renderColumnFilterModeMenuItems?: (props: {
    column: Column<TData, unknown>
    modes: FilterMode[]
    currentMode: FilterMode
    onSelect: (mode: FilterMode) => void
    table: DataTableInstance<TData>
  }) => React.ReactNode
  /** Replace the radio items in the global-search mode menu. Render your own
   *  items and call `onSelect(mode)` to switch; `modes` is the allowed set. */
  renderGlobalFilterModeMenuItems?: (props: {
    modes: GlobalFilterMode[]
    currentMode: GlobalFilterMode
    onSelect: (mode: GlobalFilterMode) => void
    table: DataTableInstance<TData>
  }) => React.ReactNode

  /** Fired when a body row is clicked / double-clicked. */
  onRowClick?: (props: RowEvent<TData>) => void
  onRowDoubleClick?: (props: RowEvent<TData>) => void
  /** Fired when a body cell is clicked / double-clicked. */
  onCellClick?: (props: CellEvent<TData>) => void
  onCellDoubleClick?: (props: CellEvent<TData>) => void

  /** Virtualize body rows for large datasets (recommended past ~100 rows).
   *  The table surface becomes the scroll container — give it a bounded height
   *  via `className`/`style` (defaults to `max-h-[600px]`). Disables row DnD. */
  enableRowVirtualization?: boolean
  /** Virtualize columns for very wide tables. Applies fixed column widths and
   *  is not combined with column pinning/ordering. */
  enableColumnVirtualization?: boolean
  /** Estimated row height (px) for the virtualizer. Default 52. */
  estimateRowHeight?: number
  /** Extra rows rendered above/below the viewport. Default 8. */
  virtualOverscan?: number
  /** Partial `@tanstack/react-virtual` options merged into the row virtualizer
   *  (overrides the built-in `count`/`estimateSize`/`overscan`/`measureElement`).
   *  Accepts an object or a `({ table }) => options` function. */
  rowVirtualizerOptions?: RowVirtualizerOptions<TData>
  /** Partial `@tanstack/react-virtual` options merged into the column
   *  virtualizer. Accepts an object or a `({ table }) => options` function. */
  columnVirtualizerOptions?: ColumnVirtualizerOptions<TData>
  /** Ref populated with the row `Virtualizer` instance for imperative control
   *  (e.g. `scrollToIndex`). Only set when `enableRowVirtualization`. */
  rowVirtualizerInstanceRef?: React.RefObject<DataTableRowVirtualizer | null>
  /** Ref populated with the column `Virtualizer` instance. Only set when
   *  `enableColumnVirtualization`. */
  columnVirtualizerInstanceRef?: React.RefObject<DataTableColumnVirtualizer | null>
  /** Show a CSV/Excel export menu in the toolbar. */
  enableExport?: boolean
  /** Base file name for exports (no extension). Default "export". */
  exportFileName?: string
  enableStickyHeader?: boolean
  enablePagination?: boolean
  /** Where the pagination controls render. Default "bottom". "none" keeps
   *  pagination active but hides the controls. */
  positionPagination?: "top" | "bottom" | "both" | "none"
  /** Pagination control style: `"default"` (range label + first/prev/next/last
   *  buttons), `"pages"` (numbered page buttons), or `"custom"` (render your own
   *  via `renderBottomToolbarCustomActions`). Default "default". */
  paginationDisplayMode?: PaginationDisplayMode
  /** Where column filter inputs live: `"subheader"` (a filter row under the
   *  header, default), `"popover"` (per-column popovers opened from the column
   *  header), or `"custom"` (you render them). */
  columnFilterDisplayMode?: ColumnFilterDisplayMode
  /** Which toolbar region the global search renders in. Default "right" (the
   *  internal-actions cluster). "left" places it next to the title/actions;
   *  "none" hides it (same as `enableGlobalFilter: false`). */
  positionGlobalFilter?: "left" | "right" | "none"
  /** Where the row-selection alert banner renders. Default "top". */
  positionToolbarAlertBanner?: "top" | "bottom" | "none"
  /** Where the group-by drop zone renders (grouping only). Default "top". */
  positionToolbarDropZone?: "top" | "bottom" | "both" | "none"
  /** Position of the auto-injected row-actions column. Default "last". */
  positionActionsColumn?: "first" | "last"
  /** Position of the auto-injected expand column (tree / detail panel).
   *  Default "first". */
  positionExpandColumn?: "first" | "last"
  /** Select-all scope for the header checkbox: the current page ("page",
   *  default) or every row ("all"). */
  selectAllMode?: "page" | "all"
  /** Show the select-all checkbox in the selection column header. Default true. */
  enableSelectAll?: boolean
  enableTopToolbar?: boolean
  enableBottomToolbar?: boolean
  /** Show the density toggle in the toolbar. Default true. */
  enableDensityToggle?: boolean
  /** Show the full-screen toggle in the toolbar. Default true. */
  enableFullscreenToggle?: boolean
  /** Show the toolbar's internal icon-action cluster (search, filters, column
   *  visibility, export, density, full screen). Default true. Hides the whole
   *  cluster at once; use the per-item flags for finer control. */
  enableToolbarInternalActions?: boolean
  enableKeyboardNavigation?: boolean
  title?: React.ReactNode
  /** Custom content rendered in the top toolbar's left region (next to the
   *  title), e.g. bulk-action buttons. */
  renderToolbarActions?: (props: DataTableSlotProps<TData>) => React.ReactNode
  /** Replace the entire top toolbar with custom content. */
  renderTopToolbar?: (props: DataTableSlotProps<TData>) => React.ReactNode
  /** Replace the entire bottom toolbar (pagination region) with custom content. */
  renderBottomToolbar?: (props: DataTableSlotProps<TData>) => React.ReactNode
  /** Replace the top toolbar's internal icon-action cluster with custom content. */
  renderToolbarInternalActions?: (
    props: DataTableSlotProps<TData>
  ) => React.ReactNode
  /** Custom content rendered in the bottom toolbar's left region (next to
   *  pagination), e.g. summary text or actions. */
  renderBottomToolbarCustomActions?: (
    props: DataTableSlotProps<TData>
  ) => React.ReactNode
  /** Render a `<caption>` for the table (e.g. an accessible summary). */
  renderCaption?: (props: DataTableSlotProps<TData>) => React.ReactNode
  renderEmpty?: (props: DataTableSlotProps<TData>) => React.ReactNode
}

"use client"

import {
  getCoreRowModel,
  getExpandedRowModel,
  getFacetedMinMaxValues,
  getFacetedRowModel,
  getFacetedUniqueValues,
  getFilteredRowModel,
  getGroupedRowModel,
  getPaginationRowModel,
  useReactTable,
  type RowData,
} from "@tanstack/react-table"
import * as React from "react"

import { VALUELESS_MODES, type FilterMode } from "../fns/filter-fns"
import { columnKey } from "../helpers/column-key"
import { getColumnLabel } from "../helpers/column-label"
import {
  getColumnDefMinWidth,
  getColumnDefPreferredWidth,
  getHeaderControlsWidth,
  isDataColumnDef,
  type HeaderControlsOptions,
} from "../helpers/header-controls"
import { measureColumnWidth } from "../helpers/measure-column-width"
import { useAdvancedFilter } from "../hooks/use-advanced-filter"
import { useColumnFilterModes } from "../hooks/use-column-filter-modes"
import { useControllableState } from "../hooks/use-controllable-state"
import { useEditingState } from "../hooks/use-editing-state"
import { useGlobalFilterMode } from "../hooks/use-global-filter-mode"
import { usePageResetOnFilterChange } from "../hooks/use-page-reset-on-filter-change"
import { useResolvedColumns } from "../hooks/use-resolved-columns"
import { useDataTableConfigContext } from "./config-context"
import { defaultIcons } from "./icons"
import { defaultLocalization } from "./localization"
import type {
  DataTableConfig,
  DataTableInstance,
  Density,
  UseDataTableOptions,
} from "./types"

/**
 * Core hook. Wraps `useReactTable` with MRT-flavoured defaults (row models,
 * auto-injected selection column, localization) and attaches our presentation
 * state + feature flags to the instance as `table.tableInstance`. Returns the
 * enriched instance to hand to `<DataTable table={table} />`.
 *
 * Controlled data state (sorting/filtering/pagination/selection/visibility),
 * `manual*` server-side flags, and `getRowId` all pass straight through to
 * TanStack via the spread options. The presentation state is split into focused
 * hooks (`use-editing-state`, `use-column-filter-modes`, `use-global-filter-mode`,
 * `use-resolved-columns`, `use-page-reset-on-filter-change`); this hook wires
 * them together and assembles the `tableInstance` config.
 */
export function useDataTable<TData extends RowData>(
  options: UseDataTableOptions<TData>
): DataTableInstance<TData> {
  const {
    localization: localizationProp,
    icons: iconsProp,
    defaultDensity = "comfortable",
    defaultShowColumnFilters = false,
    isLoading = false,
    isSaving = false,
    showProgressBars: showProgressBarsProp,
    showSkeletons: showSkeletonsProp,
    showLoadingOverlay: showLoadingOverlayProp,
    enableFacetedValues = true,
    enableColumnActions = true,
    enableStickyHeader = true,
    enablePagination = true,
    positionPagination = "bottom",
    paginationDisplayMode = "default",
    columnFilterDisplayMode = "subheader",
    positionGlobalFilter = "right",
    positionToolbarAlertBanner = "top",
    positionToolbarDropZone = "top",
    positionActionsColumn = "last",
    positionExpandColumn = "first",
    selectAllMode = "page",
    enableSelectAll = true,
    enableTopToolbar = true,
    enableBottomToolbar = true,
    enableDensityToggle = true,
    enableFullscreenToggle = true,
    enableKeyboardNavigation = true,
    enableColumnFilterModes = true,
    enableFilterMatchHighlighting = true,
    enableGlobalFilter = true,
    enableGlobalFilterModes = true,
    enableGlobalFilterRankedResults = false,
    defaultGlobalFilterMode = "fuzzy",
    density: densityProp,
    onDensityChange,
    isFullscreen: isFullscreenProp,
    onIsFullscreenChange,
    showColumnFilters: showColumnFiltersProp,
    onShowColumnFiltersChange,
    enableAdvancedFilter = false,
    advancedFilter: advancedFilterProp,
    defaultAdvancedFilter,
    onAdvancedFilterChange,
    globalFilterMode: globalFilterModeProp,
    onGlobalFilterModeChange,
    enableColumnOrdering = false,
    enableColumnPinning = false,
    enableColumnResizing = false,
    enableColumnAutosize: enableColumnAutosizeProp,
    enableRowOrdering = false,
    enableRowPinning = false,
    enableRowNumbers = false,
    rowNumberMode = "static",
    onRowOrderChange,
    enableGrouping = false,
    enableExpanding: enableExpandingProp,
    enableStickyFooter = true,
    renderDetailPanel,
    enableEditing = false,
    editDisplayMode = "cell",
    createDisplayMode = "modal",
    createRowDefaults,
    enableClickToCopy = false,
    onEditCellSave,
    onSaveRow,
    onCreateRow,
    renderRowActions,
    renderCellActionMenuItems,
    renderRowActionMenuItems,
    renderColumnActionsMenuItems,
    renderColumnFilterModeMenuItems,
    renderGlobalFilterModeMenuItems,
    renderCaption,
    onRowClick,
    onRowDoubleClick,
    onCellClick,
    onCellDoubleClick,
    enableRowVirtualization = false,
    enableColumnVirtualization = false,
    estimateRowHeight = 52,
    virtualOverscan = 8,
    rowVirtualizerOptions,
    columnVirtualizerOptions,
    rowVirtualizerInstanceRef,
    columnVirtualizerInstanceRef,
    enableExport = false,
    exportFileName,
    enableToolbarInternalActions = true,
    title,
    renderToolbarActions,
    renderTopToolbar,
    renderBottomToolbar,
    renderToolbarInternalActions,
    renderBottomToolbarCustomActions,
    renderEmpty,
    columns,
    ...tableOptions
  } = options

  // App-wide defaults from a surrounding DataTableConfigProvider (if any) sit
  // between the built-in defaults and per-call options.
  const configCtx = useDataTableConfigContext()
  const localization = React.useMemo(
    () => ({
      ...defaultLocalization,
      ...configCtx.localization,
      ...localizationProp,
    }),
    [configCtx.localization, localizationProp]
  )
  const icons = React.useMemo(
    () => ({ ...defaultIcons, ...configCtx.icons, ...iconsProp }),
    [configCtx.icons, iconsProp]
  )

  // Expansion turns on for tree data (getSubRows), detail panels, or grouping.
  const enableExpanding =
    enableExpandingProp ??
    (!!renderDetailPanel || !!tableOptions.getSubRows || enableGrouping)
  // An expand column is needed for tree sub-rows or detail panels (grouped
  // rows carry their own chevron in the grouping cell).
  const needsExpandColumn = !!renderDetailPanel || !!tableOptions.getSubRows

  // Loading affordances: each can be forced on/off, else derived from the
  // loading/saving flags (progress bar for either; skeletons + overlay only
  // for the initial data load).
  const showProgressBars = showProgressBarsProp ?? (isLoading || isSaving)
  const showSkeletons = showSkeletonsProp ?? isLoading
  const showLoadingOverlay = showLoadingOverlayProp ?? isLoading

  const [density, setDensity] = useControllableState<Density>(
    densityProp,
    defaultDensity,
    onDensityChange
  )
  const [isFullscreen, setIsFullscreen] = useControllableState(
    isFullscreenProp,
    false,
    onIsFullscreenChange
  )
  const [showColumnFilters, setShowColumnFilters] = useControllableState(
    showColumnFiltersProp,
    defaultShowColumnFilters,
    onShowColumnFiltersChange
  )

  const {
    editingCell,
    setEditingCell,
    editingRowId,
    isCreating,
    rowDraft,
    setRowDraftValue,
    beginRowEdit,
    beginCreate,
    cancelEdit,
  } = useEditingState<TData>(createRowDefaults)

  const { columnFilterModes, setColumnFilterModes, dynamicFilterFn } =
    useColumnFilterModes<TData>(columns)

  const isManualFiltering = !!tableOptions.manualFiltering

  const {
    globalFilterMode,
    setGlobalFilterMode,
    dynamicGlobalFilterFn,
    rankedSortedRowModel,
  } = useGlobalFilterMode<TData>({
    globalFilterMode: globalFilterModeProp,
    defaultGlobalFilterMode,
    onGlobalFilterModeChange,
    enableGlobalFilterRankedResults,
    manualSorting: !!tableOptions.manualSorting,
    manualFiltering: isManualFiltering,
    enableGrouping,
  })

  const {
    advancedFilter,
    setAdvancedFilter,
    showAdvancedFilterPanel,
    setShowAdvancedFilterPanel,
    advancedFilteredRowModel,
  } = useAdvancedFilter<TData>({
    enableAdvancedFilter,
    advancedFilter: advancedFilterProp,
    defaultAdvancedFilter,
    onAdvancedFilterChange,
  })

  const enableRowSelection =
    tableOptions.enableRowSelection != null
      ? !!tableOptions.enableRowSelection
      : false

  // Columns with a consumer-provided cell renderer are left untouched by
  // auto-highlighting (the consumer owns their markup).
  const columnsWithCustomCell = React.useMemo(() => {
    const set = new Set<string>()
    for (const def of columns) {
      const key = columnKey(def as { id?: string; accessorKey?: unknown })
      if (key && "cell" in def && def.cell != null) set.add(key)
    }
    return set
  }, [columns])

  const resolvedColumns = useResolvedColumns<TData>({
    columns,
    enableRowOrdering,
    enableRowSelection,
    selectAllMode,
    enableSelectAll,
    needsExpandColumn,
    positionExpandColumn,
    enableRowNumbers,
    rowNumberMode,
    enableRowPinning,
    renderRowActions,
    renderRowActionMenuItems,
    positionActionsColumn,
    enableEditing,
    editDisplayMode,
    localization,
    icons,
  })

  // Which header affordances render — shared by the column sizing below, the
  // autosize measurement, and the header components, so they can't diverge.
  const headerControlsOptions = React.useMemo<HeaderControlsOptions>(
    () => ({
      enableColumnActions,
      enableColumnOrdering,
      enableGrouping,
      enableColumnPinning,
      enableColumnVirtualization,
      columnFilterDisplayMode,
    }),
    [
      enableColumnActions,
      enableColumnOrdering,
      enableGrouping,
      enableColumnPinning,
      enableColumnVirtualization,
      columnFilterDisplayMode,
    ]
  )

  // Size each data column so its header controls are never clipped. Under
  // `table-layout: fixed` a `<th>` is pinned to `getSize()` and clips overflow,
  // and CSS `min-width` is ignored — so the drag grip / actions / filter button
  // (all shrink-0) would be hidden behind a long label or a small size.
  //  • minSize — a hard floor (controls + a sliver of label) that raises
  //    `getSize()` and stops the resize drag; the label truncates past it.
  //  • size — the at-rest default, widened to fit the full header so nothing is
  //    truncated until the user drags narrower; only when no size was pinned.
  // Done here as a pure transform (not a post-build mutation) so React Compiler
  // keeps it and the SSR and client size vars match — a mutation in a memo/effect
  // is dead-code-eliminated on the client and desyncs hydration.
  const baseColumnSize = tableOptions.defaultColumn?.size ?? 150
  const sizedColumns = React.useMemo(
    () =>
      resolvedColumns.map((def) => {
        if (!isDataColumnDef(def)) return def
        const minSize = Math.max(
          def.minSize ?? 0,
          getColumnDefMinWidth(def, headerControlsOptions)
        )
        const size =
          def.size != null
            ? def.size
            : Math.max(
                baseColumnSize,
                getColumnDefPreferredWidth(def, headerControlsOptions)
              )
        return { ...def, minSize, size }
      }),
    [resolvedColumns, headerControlsOptions, baseColumnSize]
  )

  const table = useReactTable<TData>({
    ...tableOptions,
    columns: sizedColumns,
    // Default page-reset off: TanStack's auto-reset runs a state update during
    // render (warns in React 19 dev). We reset on filter changes via an effect
    // below instead. Consumers can re-enable by passing the option explicitly.
    autoResetPageIndex: tableOptions.autoResetPageIndex ?? false,
    defaultColumn: {
      filterFn: dynamicFilterFn,
      ...tableOptions.defaultColumn,
    },
    enableGlobalFilter,
    globalFilterFn: tableOptions.globalFilterFn ?? dynamicGlobalFilterFn,
    enableColumnPinning,
    enableColumnResizing,
    columnResizeMode: tableOptions.columnResizeMode ?? "onChange",
    enableRowPinning,
    keepPinnedRows: tableOptions.keepPinnedRows ?? true,
    enableGrouping,
    enableExpanding,
    // Detail panels expand arbitrary rows; tree data uses getSubRows' own logic.
    getRowCanExpand:
      tableOptions.getRowCanExpand ??
      (renderDetailPanel ? () => true : undefined),
    getGroupedRowModel: enableGrouping
      ? (tableOptions.getGroupedRowModel ?? getGroupedRowModel())
      : tableOptions.getGroupedRowModel,
    getExpandedRowModel: enableExpanding
      ? (tableOptions.getExpandedRowModel ?? getExpandedRowModel())
      : tableOptions.getExpandedRowModel,
    getCoreRowModel: tableOptions.getCoreRowModel ?? getCoreRowModel(),
    getSortedRowModel: tableOptions.manualSorting
      ? tableOptions.getSortedRowModel
      : (tableOptions.getSortedRowModel ?? rankedSortedRowModel),
    getFilteredRowModel: isManualFiltering
      ? tableOptions.getFilteredRowModel
      : (tableOptions.getFilteredRowModel ??
        (enableAdvancedFilter
          ? advancedFilteredRowModel
          : getFilteredRowModel())),
    // Client-side faceting powers select/multi-select option lists + counts and
    // range-slider bounds. Skipped in manual mode (server supplies facets) or
    // when `enableFacetedValues` is off.
    getFacetedRowModel:
      isManualFiltering || !enableFacetedValues
        ? tableOptions.getFacetedRowModel
        : (tableOptions.getFacetedRowModel ?? getFacetedRowModel()),
    getFacetedUniqueValues:
      isManualFiltering || !enableFacetedValues
        ? tableOptions.getFacetedUniqueValues
        : (tableOptions.getFacetedUniqueValues ?? getFacetedUniqueValues()),
    getFacetedMinMaxValues:
      isManualFiltering || !enableFacetedValues
        ? tableOptions.getFacetedMinMaxValues
        : (tableOptions.getFacetedMinMaxValues ?? getFacetedMinMaxValues()),
    getPaginationRowModel:
      !enablePagination || tableOptions.manualPagination
        ? tableOptions.getPaginationRowModel
        : (tableOptions.getPaginationRowModel ?? getPaginationRowModel()),
  }) as DataTableInstance<TData>

  const enableColumnFilters = tableOptions.enableColumnFilters !== false

  usePageResetOnFilterChange(table, {
    enablePagination,
    manualPagination: tableOptions.manualPagination,
    autoResetPageIndex: tableOptions.autoResetPageIndex,
  })

  // Advanced filter edits can shrink the result set; jump back to the first
  // page so the user isn't stranded on an out-of-range page (mirrors the
  // column-filter reset above).
  const advancedFilterResetRef = React.useRef(advancedFilter)
  React.useEffect(() => {
    if (advancedFilterResetRef.current === advancedFilter) return
    advancedFilterResetRef.current = advancedFilter
    if (
      enableAdvancedFilter &&
      enablePagination &&
      !tableOptions.manualPagination
    ) {
      table.setPageIndex(0)
    }
  }, [
    advancedFilter,
    enableAdvancedFilter,
    enablePagination,
    tableOptions.manualPagination,
    table,
  ])

  // Switching a column's mode resets its value so a stale value (e.g. a
  // numeric range left over from "between") can't break the new mode. Valueless
  // modes (empty/notEmpty) get a truthy sentinel so they stay active. Lives here
  // (not in useColumnFilterModes) because it needs the table instance.
  const setColumnFilterMode = React.useCallback(
    (columnId: string, mode: FilterMode) => {
      setColumnFilterModes((prev) => ({ ...prev, [columnId]: mode }))
      const column = table.getColumn(columnId)
      if (!column) return
      column.setFilterValue(VALUELESS_MODES.has(mode) ? mode : undefined)
    },
    [table, setColumnFilterModes]
  )

  // Structural DOM refs, exposed on `table.tableInstance.refs` and attached to the
  // corresponding elements in DataTable / toolbar / global-filter.
  const tablePaperRef = React.useRef<HTMLDivElement>(null)
  const tableContainerRef = React.useRef<HTMLDivElement>(null)
  const topToolbarRef = React.useRef<HTMLDivElement>(null)
  const bottomToolbarRef = React.useRef<HTMLDivElement>(null)
  const tableHeadRef = React.useRef<HTMLTableSectionElement>(null)
  const tableFooterRef = React.useRef<HTMLTableSectionElement>(null)
  const searchInputRef = React.useRef<HTMLInputElement>(null)

  // Double-clicking a resize handle (or calling this imperatively) fits a column
  // to its widest value. Defaults on when resizing is enabled.
  const enableColumnAutosize = enableColumnAutosizeProp ?? enableColumnResizing

  const autoSizeColumn = React.useCallback(
    (columnId: string) => {
      const column = table.getColumn(columnId)
      if (!column || !column.getCanResize()) return

      // Font + horizontal padding come from a real rendered cell so measurement
      // matches the actual type scale and density; fall back to sane defaults.
      const containerEl = tableContainerRef.current
      const sampleCell =
        containerEl?.querySelector<HTMLElement>("tbody td") ??
        containerEl?.querySelector<HTMLElement>("thead th") ??
        null
      let font = "14px sans-serif"
      let padding = 24
      if (sampleCell) {
        const cs = getComputedStyle(sampleCell)
        if (cs.font) font = cs.font
        padding = parseFloat(cs.paddingLeft) + parseFloat(cs.paddingRight)
      }

      // Measure the full dataset (not just virtualized-visible rows) from raw
      // values. Headers render uppercase, so match that for measurement.
      const values = table.getRowModel().rows.map((row) => {
        const value = row.getValue(columnId)
        return value == null ? "" : String(value)
      })
      const headerText = getColumnLabel(column).toUpperCase()

      // Reserve room beside the label for the header affordances that actually
      // render (sort indicator, drag grip, column-actions trigger, popover
      // filter button). Shared with the per-column minSize floor below so
      // measurement and the floor can never disagree — see helpers/header-controls.
      const extraWidth = getHeaderControlsWidth(column, headerControlsOptions)

      const width = measureColumnWidth(values, headerText, {
        font,
        padding,
        extraWidth,
      })

      // Respect any per-column size bounds from the column def.
      const { minSize, maxSize } = column.columnDef
      let clamped = width
      if (typeof minSize === "number") clamped = Math.max(clamped, minSize)
      if (typeof maxSize === "number") clamped = Math.min(clamped, maxSize)

      table.setColumnSizing((prev) => ({ ...prev, [columnId]: clamped }))
    },
    [table, headerControlsOptions]
  )

  const autoSizeAllColumns = React.useCallback(() => {
    for (const column of table.getVisibleLeafColumns()) {
      if (column.getCanResize()) autoSizeColumn(column.id)
    }
  }, [table, autoSizeColumn])

  const config: DataTableConfig<TData> = {
    localization,
    icons,
    refs: {
      tablePaperRef,
      tableContainerRef,
      topToolbarRef,
      bottomToolbarRef,
      tableHeadRef,
      tableFooterRef,
      searchInputRef,
    },
    density,
    setDensity,
    isFullscreen,
    setIsFullscreen,
    showColumnFilters,
    setShowColumnFilters,
    columnFilterModes,
    setColumnFilterMode,
    globalFilterMode,
    setGlobalFilterMode,
    enableGlobalFilter,
    enableGlobalFilterModes,
    enableAdvancedFilter,
    advancedFilter,
    setAdvancedFilter,
    showAdvancedFilterPanel,
    setShowAdvancedFilterPanel,
    isLoading,
    isSaving,
    showProgressBars,
    showSkeletons,
    showLoadingOverlay,
    enableFacetedValues,
    enableColumnActions,
    enableColumnFilters,
    enableColumnFilterModes,
    enableFilterMatchHighlighting,
    columnsWithCustomCell,
    enableColumnOrdering,
    enableColumnPinning,
    enableColumnResizing,
    enableColumnAutosize,
    autoSizeColumn,
    autoSizeAllColumns,
    enableRowOrdering,
    enableRowPinning,
    enableRowNumbers,
    rowNumberMode,
    onRowOrderChange,
    enableGrouping,
    enableExpanding,
    enableStickyFooter,
    renderDetailPanel,
    enableEditing,
    editDisplayMode,
    createDisplayMode,
    editingCell,
    setEditingCell,
    editingRowId,
    isCreating,
    rowDraft,
    setRowDraftValue,
    beginRowEdit,
    beginCreate,
    cancelEdit,
    enableClickToCopy,
    onEditCellSave,
    onSaveRow,
    onCreateRow,
    renderRowActions,
    renderCellActionMenuItems,
    onRowClick,
    onRowDoubleClick,
    onCellClick,
    onCellDoubleClick,
    enableRowVirtualization,
    enableColumnVirtualization,
    estimateRowHeight,
    virtualOverscan,
    rowVirtualizerOptions,
    columnVirtualizerOptions,
    rowVirtualizerInstanceRef,
    columnVirtualizerInstanceRef,
    enableExport,
    exportFileName,
    enableStickyHeader,
    enablePagination,
    positionPagination,
    paginationDisplayMode,
    columnFilterDisplayMode,
    positionGlobalFilter,
    positionToolbarAlertBanner,
    positionToolbarDropZone,
    enableRowSelection,
    enableTopToolbar,
    enableBottomToolbar,
    enableDensityToggle,
    enableFullscreenToggle,
    enableToolbarInternalActions,
    enableKeyboardNavigation,
    title,
    renderToolbarActions,
    renderTopToolbar,
    renderBottomToolbar,
    renderToolbarInternalActions,
    renderBottomToolbarCustomActions,
    renderRowActionMenuItems,
    renderColumnActionsMenuItems,
    renderColumnFilterModeMenuItems,
    renderGlobalFilterModeMenuItems,
    renderCaption,
    renderEmpty,
  }

  table.tableInstance = config

  return table
}

import {
  getFilteredRowModel,
  type Row,
  type RowData,
  type RowModel,
  type Table,
} from "@tanstack/react-table"

import type {
  AdvancedFilterGroup,
  AdvancedFilterOperator,
  AdvancedFilterRule,
  FilterVariant,
} from "../core/types"

/** A value that contributes nothing to a filter (no cell value / no input). */
function isEmptyValue(value: unknown): boolean {
  return (
    value == null ||
    value === "" ||
    (Array.isArray(value) && value.length === 0)
  )
}

/** Parse a number from a value, or null if it isn't numeric. */
function asNumber(value: unknown): number | null {
  if (typeof value === "number") return Number.isNaN(value) ? null : value
  if (typeof value === "string" && value.trim() !== "") {
    const n = Number(value)
    return Number.isNaN(n) ? null : n
  }
  return null
}

/** Parse an epoch time from a Date or date-ish string, or null. */
function asTime(value: unknown): number | null {
  if (value instanceof Date) return value.getTime()
  if (typeof value === "string" && value.trim() !== "") {
    const t = Date.parse(value)
    return Number.isNaN(t) ? null : t
  }
  return null
}

/** Order two cell-ish values: numeric first, then date, then string. */
function compareValues(a: unknown, b: unknown): number {
  const na = asNumber(a)
  const nb = asNumber(b)
  if (na != null && nb != null) return na - nb
  const ta = asTime(a)
  const tb = asTime(b)
  if (ta != null && tb != null) return ta - tb
  return String(a).localeCompare(String(b))
}

/** Loose equality: numeric when both sides parse as numbers, else case- and
 *  whitespace-insensitive string compare (so "Active" matches a "active" rule). */
function looseEquals(cell: unknown, value: unknown): boolean {
  const nc = asNumber(cell)
  const nv = asNumber(value)
  if (nc != null && nv != null) return nc === nv
  if (typeof cell === "boolean" || typeof value === "boolean") {
    return String(cell) === String(value)
  }
  return (
    String(cell).trim().toLowerCase() === String(value).trim().toLowerCase()
  )
}

const VALUELESS_OPERATORS: ReadonlySet<AdvancedFilterOperator> = new Set([
  "isEmpty",
  "isNotEmpty",
])

/**
 * Evaluate one operator against a cell value. Rules whose value input is
 * incomplete are treated as inactive (return true) so a half-typed rule doesn't
 * blank the table. An empty cell only matches `isEmpty` / `notEquals` /
 * `notContains`; every other operator needs a value to compare against.
 */
export function applyOperator(
  cellValue: unknown,
  operator: AdvancedFilterOperator,
  value: unknown,
  value2: unknown
): boolean {
  if (operator === "isEmpty") return isEmptyValue(cellValue)
  if (operator === "isNotEmpty") return !isEmptyValue(cellValue)

  const cellEmpty = isEmptyValue(cellValue)

  if (operator === "between") {
    if (isEmptyValue(value) || isEmptyValue(value2)) return true
    if (cellEmpty) return false
    const lo = compareValues(cellValue, value)
    const hi = compareValues(cellValue, value2)
    return lo >= 0 && hi <= 0
  }

  // A value-requiring operator with no value is inactive.
  if (isEmptyValue(value)) return true

  if (operator === "notEquals")
    return cellEmpty || !looseEquals(cellValue, value)
  if (operator === "notContains") {
    return (
      cellEmpty ||
      !String(cellValue).toLowerCase().includes(String(value).toLowerCase())
    )
  }

  // Remaining operators can't match an empty cell.
  if (cellEmpty) return false

  switch (operator) {
    case "equals":
      return looseEquals(cellValue, value)
    case "contains":
      return String(cellValue)
        .toLowerCase()
        .includes(String(value).toLowerCase())
    case "startsWith":
      return String(cellValue)
        .toLowerCase()
        .startsWith(String(value).toLowerCase())
    case "endsWith":
      return String(cellValue)
        .toLowerCase()
        .endsWith(String(value).toLowerCase())
    case "greaterThan":
      return compareValues(cellValue, value) > 0
    case "greaterThanOrEqual":
      return compareValues(cellValue, value) >= 0
    case "lessThan":
      return compareValues(cellValue, value) < 0
    case "lessThanOrEqual":
      return compareValues(cellValue, value) <= 0
    default:
      return true
  }
}

/** Evaluate a single rule against a row. */
export function evaluateRule<TData extends RowData>(
  row: Row<TData>,
  rule: AdvancedFilterRule
): boolean {
  return applyOperator(
    row.getValue(rule.columnId),
    rule.operator,
    rule.value,
    rule.value2
  )
}

/** Evaluate the whole group against a row (AND/OR over its rules). */
export function evaluateAdvancedFilterGroup<TData extends RowData>(
  row: Row<TData>,
  group: AdvancedFilterGroup
): boolean {
  if (group.rules.length === 0) return true
  return group.logic === "and"
    ? group.rules.every((rule) => evaluateRule(row, rule))
    : group.rules.some((rule) => evaluateRule(row, rule))
}

/** Operators offered for a column, by its filter variant. */
export function getOperatorsForVariant(
  variant: FilterVariant
): AdvancedFilterOperator[] {
  switch (variant) {
    case "select":
    case "multi-select":
      return ["equals", "notEquals", "isEmpty", "isNotEmpty"]
    case "range":
    case "range-slider":
      return [
        "equals",
        "notEquals",
        "greaterThan",
        "greaterThanOrEqual",
        "lessThan",
        "lessThanOrEqual",
        "between",
        "isEmpty",
        "isNotEmpty",
      ]
    case "date":
    case "date-range":
      return [
        "equals",
        "notEquals",
        "greaterThan",
        "lessThan",
        "between",
        "isEmpty",
        "isNotEmpty",
      ]
    case "checkbox":
      return ["equals"]
    default:
      return [
        "contains",
        "notContains",
        "startsWith",
        "endsWith",
        "equals",
        "notEquals",
        "isEmpty",
        "isNotEmpty",
      ]
  }
}

/** Whether an operator hides its value input(s). */
export function isValuelessOperator(operator: AdvancedFilterOperator): boolean {
  return VALUELESS_OPERATORS.has(operator)
}

/** Rebuild a row model from a filtered set of top-level rows, recomputing the
 *  flat list + id map from the kept rows and their descendants. */
function filterRowModel<TData extends RowData>(
  model: RowModel<TData>,
  predicate: (row: Row<TData>) => boolean
): RowModel<TData> {
  const rows = model.rows.filter(predicate)
  const flatRows: Row<TData>[] = []
  const rowsById: Record<string, Row<TData>> = {}
  const collect = (rs: Row<TData>[]) => {
    for (const row of rs) {
      flatRows.push(row)
      rowsById[row.id] = row
      if (row.subRows.length) collect(row.subRows)
    }
  }
  collect(rows)
  return { rows, flatRows, rowsById }
}

/**
 * Wraps TanStack's filtered row model and additionally applies the advanced
 * filter group on top, so both filter systems are active simultaneously. The
 * group is read through `getGroup` at evaluation time (the factory keeps a
 * stable identity to preserve memoization), and results are cached per
 * underlying model + group so they only recompute when something changes.
 */
export function createAdvancedFilteredRowModel<TData extends RowData>(
  getGroup: () => AdvancedFilterGroup
): (table: Table<TData>) => () => RowModel<TData> {
  const base = getFilteredRowModel<TData>()
  return (table) => {
    const delegate = base(table)
    let cachedFor: RowModel<TData> | null = null
    let cachedGroup: AdvancedFilterGroup | null = null
    let cached: RowModel<TData> | null = null
    return () => {
      const model = delegate()
      const group = getGroup()
      if (group.rules.length === 0) return model
      if (cached && cachedFor === model && cachedGroup === group) return cached
      cached = filterRowModel(model, (row) =>
        evaluateAdvancedFilterGroup(row, group)
      )
      cachedFor = model
      cachedGroup = group
      return cached
    }
  }
}

import type { FilterFn, RowData } from "@tanstack/react-table"
import { rankItem } from "@tanstack/match-sorter-utils"

import {
  MODE_FNS,
  isInactive,
  type FilterMode,
  type GlobalFilterMode,
} from "./filter-modes"

/**
 * Single dynamic filter function assigned to every column via `defaultColumn`.
 * It reads the column's current mode from the provided lookup and dispatches.
 * Mode state lives in the hook; this closure reads it through `getMode` (a ref
 * getter) so the function identity stays stable across renders.
 */
export function createDynamicFilterFn<TData extends RowData>(
  getMode: (columnId: string) => FilterMode
): FilterFn<TData> {
  const fn: FilterFn<TData> = (row, columnId, filterValue) => {
    const mode = getMode(columnId)
    const modeFn = MODE_FNS[mode] ?? MODE_FNS.contains
    return modeFn(row.getValue(columnId), filterValue)
  }
  // Keep valueless modes active even with a blank value; otherwise drop blanks.
  fn.autoRemove = (value) => isInactive(value)
  return fn
}

/**
 * Mode-aware global search. `fuzzy` uses match-sorter's `rankItem` (MRT's own
 * choice); other modes reuse the column mode functions. Matches across every
 * searchable column (TanStack runs this per column and ORs the results).
 */
export function createGlobalFilterFn<TData extends RowData>(
  getMode: () => GlobalFilterMode
): FilterFn<TData> {
  const fn: FilterFn<TData> = (row, columnId, filterValue, addMeta) => {
    const value = String(filterValue ?? "")
    if (value === "") return true
    const mode = getMode()
    if (mode === "fuzzy") {
      // Stash the rank so `enableGlobalFilterRankedResults` can order rows by
      // match quality; `rankGlobalFuzzy` reads it back off columnFiltersMeta.
      const itemRank = rankItem(row.getValue(columnId), value)
      addMeta(itemRank)
      return itemRank.passed
    }
    const modeFn = MODE_FNS[mode] ?? MODE_FNS.contains
    return modeFn(row.getValue(columnId), value)
  }
  fn.autoRemove = (value) => value == null || value === ""
  return fn
}

// Barrel for the filtering engine. Internal modules:
//   filter-modes.ts     — mode predicates (MODE_FNS), value coercers, mode sets
//   filter-factories.ts — the per-column / global dynamic FilterFn factories
//   ranked-row-model.ts — fuzzy-rank sorted row model
//   variant-modes.ts    — variant → default mode + mode-menu options
// Most of the module imports from here ("../fns/filter-fns"); keep this surface
// stable when adding to the sub-modules.

export {
  MODE_FNS,
  VALUELESS_MODES,
  SUBSTRING_MODES,
  isInactive,
  type FilterMode,
  type GlobalFilterMode,
} from "./filter-modes"
export { createDynamicFilterFn, createGlobalFilterFn } from "./filter-factories"
export { rankGlobalFuzzy, createRankedSortedRowModel } from "./ranked-row-model"
export { defaultModeForVariant, modeOptionsForVariant } from "./variant-modes"

/** Global-search modes offered in the global filter-mode menu. */
export type GlobalFilterMode =
  | "fuzzy"
  | "contains"
  | "startsWith"
  | "endsWith"
  | "equals"

/** All supported filter modes across variants. */
export type FilterMode =
  // text
  | "contains"
  | "equals"
  | "notEquals"
  | "startsWith"
  | "endsWith"
  | "fuzzy"
  // shared
  | "empty"
  | "notEmpty"
  // numeric
  | "between"
  | "betweenInclusive"
  | "greaterThan"
  | "greaterThanOrEqualTo"
  | "lessThan"
  | "lessThanOrEqualTo"
  // date
  | "before"
  | "after"
  | "betweenDates"
  // fixed (no mode menu)
  | "equalsString"
  | "arrIncludesSome"
  | "equalsBool"

import { isAfter, isBefore, startOfDay } from "date-fns"

const str = (v: unknown): string => (v == null ? "" : String(v))
const lower = (v: unknown): string => str(v).toLowerCase()
const num = (v: unknown): number =>
  typeof v === "number" ? v : parseFloat(str(v))
const isBlank = (v: unknown): boolean =>
  v == null || v === "" || (Array.isArray(v) && v.length === 0)
const toDate = (v: unknown): Date | null => {
  if (v == null || v === "") return null
  const d = v instanceof Date ? v : new Date(v as string)
  return Number.isNaN(d.getTime()) ? null : d
}

// Each entry: (row value already resolved) decides inclusion. The dynamic
// `filterFn` resolves `row.getValue(columnId)` and dispatches by mode.
type ModeFn = (cellValue: unknown, filterValue: unknown) => boolean

export const MODE_FNS: Record<FilterMode, ModeFn> = {
  contains: (cell, val) => lower(cell).includes(lower(val)),
  equals: (cell, val) => lower(cell) === lower(val),
  notEquals: (cell, val) => lower(cell) !== lower(val),
  startsWith: (cell, val) => lower(cell).startsWith(lower(val)),
  endsWith: (cell, val) => lower(cell).endsWith(lower(val)),
  fuzzy: (cell, val) => lower(cell).includes(lower(val)),

  empty: (cell) => isBlank(cell),
  notEmpty: (cell) => !isBlank(cell),

  greaterThan: (cell, val) => num(cell) > num(val),
  greaterThanOrEqualTo: (cell, val) => num(cell) >= num(val),
  lessThan: (cell, val) => num(cell) < num(val),
  lessThanOrEqualTo: (cell, val) => num(cell) <= num(val),
  between: (cell, val) => betweenNum(cell, val, false),
  betweenInclusive: (cell, val) => betweenNum(cell, val, true),

  before: (cell, val) => {
    const c = toDate(cell)
    const v = toDate(val)
    return c != null && v != null && isBefore(c, startOfDay(v))
  },
  after: (cell, val) => {
    const c = toDate(cell)
    const v = toDate(val)
    return c != null && v != null && isAfter(c, startOfDay(v))
  },
  betweenDates: (cell, val) => {
    const c = toDate(cell)
    const range = (Array.isArray(val) ? val : []) as unknown[]
    const from = toDate(range[0])
    const to = toDate(range[1])
    if (c == null) return false
    if (from != null && isBefore(c, startOfDay(from))) return false
    if (to != null && isAfter(c, startOfDay(to))) return false
    return from != null || to != null
  },

  equalsString: (cell, val) => str(cell) === str(val),
  arrIncludesSome: (cell, val) => {
    const arr = (Array.isArray(val) ? val : []) as unknown[]
    if (arr.length === 0) return true
    return arr.map(str).includes(str(cell))
  },
  equalsBool: (cell, val) => Boolean(cell) === Boolean(val),
}

function betweenNum(cell: unknown, val: unknown, inclusive: boolean): boolean {
  const arr = (Array.isArray(val) ? val : []) as unknown[]
  const n = num(cell)
  if (Number.isNaN(n)) return false
  const min = arr[0] === "" || arr[0] == null ? null : num(arr[0])
  const max = arr[1] === "" || arr[1] == null ? null : num(arr[1])
  if (min != null && (inclusive ? n < min : n <= min)) return false
  if (max != null && (inclusive ? n > max : n >= max)) return false
  return min != null || max != null
}

/** Modes that activate without a typed value (they test the cell only). */
export const VALUELESS_MODES: ReadonlySet<FilterMode> = new Set([
  "empty",
  "notEmpty",
])

/** Modes whose string value should drive match highlighting in cells. */
export const SUBSTRING_MODES: ReadonlySet<FilterMode> = new Set([
  "contains",
  "startsWith",
  "endsWith",
  "equals",
  "fuzzy",
])

/**
 * A value is "inactive" (filter should auto-remove) when blank — unless the
 * mode is valueless, where any truthy sentinel keeps it active.
 */
export function isInactive(value: unknown): boolean {
  if (Array.isArray(value)) return value.every((v) => v == null || v === "")
  return value == null || value === ""
}

import {
  getSortedRowModel,
  type Row,
  type RowData,
  type RowModel,
  type Table,
} from "@tanstack/react-table"
import type { RankingInfo } from "@tanstack/match-sorter-utils"

/**
 * Descending comparator over the best fuzzy rank a row earned across the
 * columns the global search ran on. Drives `enableGlobalFilterRankedResults`.
 * Ranks are written to `row.columnFiltersMeta` by the fuzzy branch of
 * `createGlobalFilterFn`; only that branch writes meta, so this never picks up
 * per-column filter state.
 */
export function rankGlobalFuzzy<TData extends RowData>(
  rowA: Row<TData>,
  rowB: Row<TData>
): number {
  const best = (row: Row<TData>): number => {
    let max = -Infinity
    for (const meta of Object.values(row.columnFiltersMeta)) {
      const rank = (meta as RankingInfo | undefined)?.rank
      if (rank != null && rank > max) max = rank
    }
    return max === -Infinity ? 0 : max
  }
  return best(rowB) - best(rowA)
}

/**
 * Wraps TanStack's sorted row model. When `isActive(table)` is true (the caller
 * decides: fuzzy global search on, no user sort, no grouping/expansion), the
 * top-level rows are re-ordered by best fuzzy rank; otherwise the normal sorted
 * model passes through untouched. Re-ordering at the sorted-model layer means
 * pagination, pinning, and the body all observe the ranked order with no extra
 * wiring. The result is cached per underlying model object, so the sort only
 * re-runs when filtering/sorting/data actually change.
 */
export function createRankedSortedRowModel<TData extends RowData>(
  isActive: (table: Table<TData>) => boolean
): (table: Table<TData>) => () => RowModel<TData> {
  const base = getSortedRowModel<TData>()
  return (table) => {
    const delegate = base(table)
    let cachedFor: RowModel<TData> | null = null
    let cached: RowModel<TData> | null = null
    return () => {
      const model = delegate()
      if (!isActive(table)) return model
      if (cached && cachedFor === model) return cached
      cached = { ...model, rows: [...model.rows].sort(rankGlobalFuzzy) }
      cachedFor = model
      return cached
    }
  }
}

/** Best-effort column id used to key per-column state (e.g. filter modes). */
export function columnKey(def: {
  id?: string
  accessorKey?: unknown
}): string | null {
  if (def.id) return def.id
  if (typeof def.accessorKey === "string") return def.accessorKey
  return null
}

import type { Column, RowData } from "@tanstack/react-table"

/** Best-effort human label for a column: explicit meta.label, else its
 *  string header, else its id. */
export function getColumnLabel<TData extends RowData, TValue>(
  column: Column<TData, TValue>
): string {
  const meta = column.columnDef.meta
  if (meta?.label) return meta.label
  const header = column.columnDef.header
  if (typeof header === "string" && header.length > 0) return header
  return column.id
}

import type { Column, RowData } from "@tanstack/react-table"

import type { DataTableInstance } from "../core/types"
import { defaultModeForVariant, type FilterMode } from "../fns/filter-fns"

/** Effective filter mode for a column: explicit selection → meta → variant default. */
export function getEffectiveMode<TData extends RowData, TValue>(
  column: Column<TData, TValue>,
  table: DataTableInstance<TData>
): FilterMode {
  const variant = column.columnDef.meta?.variant ?? "text"
  return (
    table.tableInstance.columnFilterModes[column.id] ??
    column.columnDef.meta?.filterMode ??
    defaultModeForVariant(variant)
  )
}

import type { Column, ColumnDef, RowData } from "@tanstack/react-table"

import { DISPLAY_COLUMN_IDS } from "../core/constants"
import type { ColumnFilterDisplayMode, DataTableInstance } from "../core/types"

/**
 * Feature flags that decide which affordances a column header renders. Single
 * source of truth so the autosize measurement, the per-column minimum width,
 * and the header components themselves can never disagree about what shows (the
 * disagreement that let controls get clipped under the fixed table layout).
 */
export interface HeaderControlsOptions {
  enableColumnActions: boolean
  enableColumnOrdering: boolean
  enableGrouping: boolean
  enableColumnPinning: boolean
  enableColumnVirtualization: boolean
  columnFilterDisplayMode: ColumnFilterDisplayMode
}

// size-7 (28px) icon button + the header's gap-0.5 (2px) between affordances.
const ICON_BUTTON_WIDTH = 30
// The sort glyph + its gap, rendered inside the label button.
const SORT_INDICATOR_WIDTH = 20
// Horizontal cell padding + a sliver of label, so a column never collapses to
// controls-only. A coarse constant: the exact (density-dependent) padding isn't
// knowable without the DOM, and over-reserving a few px is harmless.
const LABEL_AND_PADDING_MIN = 56
// Rough width of one uppercase, letter-spaced header character at the header's
// text-xs scale. Deterministic (no canvas) so the SSR and client size vars
// agree — a canvas measurement would differ between them and warn on hydration.
const HEADER_CHAR_WIDTH = 8.5
// Horizontal cell padding reserved around the header label.
const HEADER_PADDING = 24
// Cap so a very long header can't create an enormous default column.
const HEADER_LABEL_MAX = 260

/** Build {@link HeaderControlsOptions} from a live table's resolved config. */
export function headerControlsOptionsFromTable<TData extends RowData>(
  table: DataTableInstance<TData>
): HeaderControlsOptions {
  const config = table.tableInstance
  return {
    enableColumnActions: config.enableColumnActions,
    enableColumnOrdering: config.enableColumnOrdering,
    enableGrouping: config.enableGrouping,
    enableColumnPinning: config.enableColumnPinning,
    enableColumnVirtualization: config.enableColumnVirtualization,
    columnFilterDisplayMode: config.columnFilterDisplayMode,
  }
}

/** Whether the column-reorder drag grip renders in this column's header. */
export function shouldShowColumnDragGrip<TData extends RowData, TValue>(
  column: Column<TData, TValue>,
  opts: HeaderControlsOptions
): boolean {
  if (DISPLAY_COLUMN_IDS.has(column.id)) return false
  return (
    (opts.enableColumnOrdering ||
      (opts.enableGrouping && column.getCanGroup())) &&
    !opts.enableColumnVirtualization &&
    !column.getIsPinned()
  )
}

/** Whether the column-actions (⋮) trigger renders in this column's header. */
export function shouldShowColumnActions<TData extends RowData, TValue>(
  column: Column<TData, TValue>,
  opts: HeaderControlsOptions
): boolean {
  return (
    opts.enableColumnActions &&
    !column.columnDef.meta?.disableColumnActions &&
    (column.getCanSort() ||
      column.getCanHide() ||
      column.getCanFilter() ||
      (opts.enableColumnPinning && column.getCanPin()) ||
      (opts.enableGrouping && column.getCanGroup()))
  )
}

/** Whether the popover filter button renders in this column's header. */
export function shouldShowColumnFilterButton<TData extends RowData, TValue>(
  column: Column<TData, TValue>,
  opts: HeaderControlsOptions
): boolean {
  return opts.columnFilterDisplayMode === "popover" && column.getCanFilter()
}

/**
 * Width (px) to reserve beside the label for the header affordances that will
 * actually render for this column — the sort indicator plus any of the drag
 * grip, actions trigger, and filter button. Used as `extraWidth` when
 * autosizing and as the controls portion of {@link getHeaderControlsMinWidth}.
 */
export function getHeaderControlsWidth<TData extends RowData, TValue>(
  column: Column<TData, TValue>,
  opts: HeaderControlsOptions
): number {
  return (
    (column.getCanSort() ? SORT_INDICATOR_WIDTH : 0) +
    (shouldShowColumnDragGrip(column, opts) ? ICON_BUTTON_WIDTH : 0) +
    (shouldShowColumnActions(column, opts) ? ICON_BUTTON_WIDTH : 0) +
    (shouldShowColumnFilterButton(column, opts) ? ICON_BUTTON_WIDTH : 0)
  )
}

// ----------------------------------------------------------------------------
// ColumnDef-based reservation
//
// The functions above read a *built* column (capabilities via getCan*). The
// size/minSize floors, however, must be baked into the column defs *before*
// `useReactTable` — a pure transform, so React Compiler keeps it and SSR/client
// agree (mutating a built column in an effect/memo gets dead-code-eliminated on
// the client and desyncs hydration). These mirror the predicates above but
// derive capabilities from the def + flags. They err toward reserving (a column
// counts as sortable/filterable unless explicitly disabled) so the reservation
// is always ≥ what actually renders — controls can never end up clipped.
// ----------------------------------------------------------------------------

type AnyColumnDef<TData extends RowData> = ColumnDef<TData, unknown> & {
  accessorKey?: unknown
  accessorFn?: unknown
  columns?: unknown
  enableSorting?: boolean
  enableHiding?: boolean
  enableColumnFilter?: boolean
  enableGrouping?: boolean
  enablePinning?: boolean
  minSize?: number
  size?: number
}

function hasAccessor<TData extends RowData>(def: AnyColumnDef<TData>): boolean {
  return def.accessorKey != null || def.accessorFn != null
}

function defLabel<TData extends RowData>(def: AnyColumnDef<TData>): string {
  if (def.meta?.label) return def.meta.label
  if (typeof def.header === "string" && def.header.length > 0) return def.header
  if (typeof def.accessorKey === "string") return def.accessorKey
  return ""
}

function getColumnDefControlsWidth<TData extends RowData>(
  def: AnyColumnDef<TData>,
  opts: HeaderControlsOptions
): number {
  const canSort = def.enableSorting !== false && hasAccessor(def)
  const canHide = def.enableHiding !== false
  const canFilter = def.enableColumnFilter !== false && hasAccessor(def)
  const canGroup = def.enableGrouping !== false && hasAccessor(def)
  const canPin = def.enablePinning !== false

  const showGrip =
    (opts.enableColumnOrdering || (opts.enableGrouping && canGroup)) &&
    !opts.enableColumnVirtualization
  const showActions =
    opts.enableColumnActions &&
    !def.meta?.disableColumnActions &&
    (canSort ||
      canHide ||
      canFilter ||
      (opts.enableColumnPinning && canPin) ||
      (opts.enableGrouping && canGroup))
  const showFilter = opts.columnFilterDisplayMode === "popover" && canFilter

  return (
    (canSort ? SORT_INDICATOR_WIDTH : 0) +
    (showGrip ? ICON_BUTTON_WIDTH : 0) +
    (showActions ? ICON_BUTTON_WIDTH : 0) +
    (showFilter ? ICON_BUTTON_WIDTH : 0)
  )
}

/** {@link getHeaderControlsMinWidth} computed from a column def (pre-build). */
export function getColumnDefMinWidth<TData extends RowData>(
  def: ColumnDef<TData, unknown>,
  opts: HeaderControlsOptions
): number {
  return LABEL_AND_PADDING_MIN + getColumnDefControlsWidth(def, opts)
}

/** {@link getHeaderPreferredWidth} computed from a column def (pre-build). */
export function getColumnDefPreferredWidth<TData extends RowData>(
  def: ColumnDef<TData, unknown>,
  opts: HeaderControlsOptions
): number {
  const labelWidth = Math.min(
    HEADER_LABEL_MAX,
    defLabel(def).length * HEADER_CHAR_WIDTH
  )
  return Math.ceil(
    HEADER_PADDING + labelWidth + getColumnDefControlsWidth(def, opts)
  )
}

/** True for a leaf user/data column def (not an injected display column or a
 *  header group) — the only defs that get a control-aware size/minSize. */
export function isDataColumnDef<TData extends RowData>(
  def: ColumnDef<TData, unknown>
): boolean {
  const anyDef = def as AnyColumnDef<TData>
  if (Array.isArray(anyDef.columns)) return false
  if (def.id != null && DISPLAY_COLUMN_IDS.has(def.id)) return false
  return hasAccessor(anyDef)
}

import type { Column, RowData } from "@tanstack/react-table"

/** A column is editable when it has an accessor and isn't opted out via meta. */
export function isColumnEditable<TData extends RowData, TValue>(
  column: Column<TData, TValue>
): boolean {
  return (
    column.accessorFn != null && column.columnDef.meta?.enableEditing !== false
  )
}

export interface MeasureColumnWidthOptions {
  /** CSS `font` shorthand read from a rendered cell (e.g. `getComputedStyle(cell).font`). */
  font: string
  /** Total horizontal cell padding (left + right) in px. */
  padding: number
  /** Extra space for header affordances (sort icon, actions trigger). Default 0. */
  extraWidth?: number
  /** Lower bound for the result. Default 0. */
  minWidth?: number
  /** Upper bound, to stop one long value producing an absurd column. Default 400. */
  maxWidth?: number
}

// A single reused canvas keeps text measurement off the DOM (no reflow) and
// avoids allocating a canvas per call.
let sharedCtx: CanvasRenderingContext2D | null | undefined

function getContext(): CanvasRenderingContext2D | null {
  if (sharedCtx !== undefined) return sharedCtx
  if (typeof document === "undefined") {
    sharedCtx = null
    return null
  }
  sharedCtx = document.createElement("canvas").getContext("2d")
  return sharedCtx
}

/**
 * Measure the width a column needs to fit its widest value without wrapping.
 *
 * Pure + framework-free: canvas text measurement means it covers the full
 * dataset (not just the rows currently rendered under virtualization), at the
 * cost of not accounting for custom cell markup — it measures the raw string
 * values the caller passes in. Falls back to a rough character estimate when no
 * canvas is available (non-browser environments).
 */
export function measureColumnWidth(
  values: string[],
  headerText: string,
  options: MeasureColumnWidthOptions
): number {
  const {
    font,
    padding,
    extraWidth = 0,
    minWidth = 0,
    maxWidth = 400,
  } = options
  const ctx = getContext()

  let contentWidth: number
  if (ctx) {
    ctx.font = font
    contentWidth = ctx.measureText(headerText).width
    for (const value of values) {
      const width = ctx.measureText(value).width
      if (width > contentWidth) contentWidth = width
    }
  } else {
    // ~8px per character is a coarse fallback for non-browser environments.
    const longest = values.reduce(
      (max, v) => (v.length > max ? v.length : max),
      headerText.length
    )
    contentWidth = longest * 8
  }

  const total = Math.ceil(contentWidth + padding + extraWidth)
  return Math.max(minWidth, Math.min(maxWidth, total))
}

