import * as React from "react"
import type { FilterFn, RowData, RowModel, Table } from "@tanstack/react-table"

import {
  createGlobalFilterFn,
  createRankedSortedRowModel,
  type GlobalFilterMode,
} from "../fns/filter-fns"
import { useControllableState } from "./use-controllable-state"

interface UseGlobalFilterModeParams {
  globalFilterMode?: GlobalFilterMode
  defaultGlobalFilterMode: GlobalFilterMode
  onGlobalFilterModeChange?: (mode: GlobalFilterMode) => void
  enableGlobalFilterRankedResults: boolean
  manualSorting: boolean
  manualFiltering: boolean
  enableGrouping: boolean
}

export interface GlobalFilterModeState<TData extends RowData> {
  globalFilterMode: GlobalFilterMode
  setGlobalFilterMode: (mode: GlobalFilterMode) => void
  /** Mode-aware global filter fn (new identity per mode → re-runs filtering). */
  dynamicGlobalFilterFn: FilterFn<TData>
  /** Sorted row model that re-orders by fuzzy rank when ranking is active. */
  rankedSortedRowModel: (table: Table<TData>) => () => RowModel<TData>
}

/**
 * Global-search mode state plus the two row-model pieces it drives: the
 * mode-aware global filter fn and the fuzzy-ranked sorted row model. While a
 * fuzzy global search is active and the user hasn't sorted, rows are ordered by
 * best match; the current config is read through a ref so the model factory
 * keeps a stable identity (recreating it would defeat TanStack's memoization).
 */
export function useGlobalFilterMode<TData extends RowData>({
  globalFilterMode: globalFilterModeProp,
  defaultGlobalFilterMode,
  onGlobalFilterModeChange,
  enableGlobalFilterRankedResults,
  manualSorting,
  manualFiltering,
  enableGrouping,
}: UseGlobalFilterModeParams): GlobalFilterModeState<TData> {
  const [globalFilterMode, setGlobalFilterMode] =
    useControllableState<GlobalFilterMode>(
      globalFilterModeProp,
      defaultGlobalFilterMode,
      onGlobalFilterModeChange
    )

  // Recreating the fn when the mode changes gives it a new identity, which
  // makes TanStack re-run global filtering with the new mode immediately.
  const dynamicGlobalFilterFn = React.useMemo(
    () => createGlobalFilterFn<TData>(() => globalFilterMode),
    [globalFilterMode]
  )

  const rankingRef = React.useRef<{
    enabled: boolean
    mode: GlobalFilterMode
    manualSorting: boolean
    manualFiltering: boolean
    grouping: boolean
  }>(null!)
  rankingRef.current = {
    enabled: enableGlobalFilterRankedResults,
    mode: globalFilterMode,
    manualSorting,
    manualFiltering,
    grouping: enableGrouping,
  }
  const rankedSortedRowModel = React.useMemo(
    () =>
      createRankedSortedRowModel<TData>((t) => {
        const c = rankingRef.current
        if (!c.enabled || c.mode !== "fuzzy") return false
        if (c.manualSorting || c.manualFiltering) return false
        const s = t.getState()
        if (!s.globalFilter) return false
        if (s.sorting.some(Boolean)) return false
        if (c.grouping && s.grouping.length > 0) return false
        if (s.expanded === true || Object.values(s.expanded).some(Boolean))
          return false
        return true
      }),
    []
  )

  return {
    globalFilterMode,
    setGlobalFilterMode,
    dynamicGlobalFilterFn,
    rankedSortedRowModel,
  }
}

"use client"

import * as React from "react"
import type { RowData } from "@tanstack/react-table"

import type { DataTableInstance } from "../core/types"

interface PageResetParams {
  enablePagination: boolean
  manualPagination?: boolean
  autoResetPageIndex?: boolean
}

/**
 * Clamps to the first page when the filter set changes (MRT behaviour),
 * replacing TanStack's render-phase auto-reset (which warns in React 19 dev).
 * Runs after mount so there is no state update during render. Skipped under
 * manual pagination (server owns it) and when the consumer opted into the
 * native auto-reset.
 */
export function usePageResetOnFilterChange<TData extends RowData>(
  table: DataTableInstance<TData>,
  { enablePagination, manualPagination, autoResetPageIndex }: PageResetParams
): void {
  const columnFiltersKey = JSON.stringify(table.getState().columnFilters)
  const globalFilterValue = table.getState().globalFilter
  const didMountRef = React.useRef(false)
  React.useEffect(() => {
    if (!didMountRef.current) {
      didMountRef.current = true
      return
    }
    if (enablePagination && !manualPagination && autoResetPageIndex == null) {
      table.setPageIndex(0)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [columnFiltersKey, globalFilterValue])
}

"use client"

import {
  KeyboardSensor,
  PointerSensor,
  closestCenter,
  pointerWithin,
  useSensor,
  useSensors,
  type CollisionDetection,
  type DragEndEvent,
} from "@dnd-kit/core"
import { arrayMove, sortableKeyboardCoordinates } from "@dnd-kit/sortable"
import type { RowData } from "@tanstack/react-table"

import { GROUP_DROPZONE_ID } from "../components/toolbar/data-table-grouping"
import type { DataTableInstance } from "../core/types"

/**
 * Sensors + drag-end handler for the single `DndContext` that drives both
 * column and row reordering. The active item's `data.type` (set in useSortable)
 * routes to the right handler — two nested contexts can't be used: dnd-kit
 * renders an a11y `<div>` that is invalid inside `<tbody>`, and a body-wrapping
 * context would swallow header drags.
 */
export function useTableDnd<TData extends RowData>(
  table: DataTableInstance<TData>
) {
  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 5 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  )

  // The group drop zone should accept a drop anywhere inside its bounds, not
  // only near its center. Prefer a pointer-within hit on the zone; otherwise
  // fall back to closestCenter for column/row reordering (and keyboard dnd,
  // where pointerWithin yields nothing).
  const collisionDetection: CollisionDetection = (args) => {
    const groupHit = pointerWithin(args).find((c) => c.id === GROUP_DROPZONE_ID)
    return groupHit ? [groupHit] : closestCenter(args)
  }

  const onRowOrderChange = table.tableInstance.onRowOrderChange

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event
    if (!over) return
    const type = active.data.current?.type

    if (type === "row") {
      if (active.id !== over.id) {
        onRowOrderChange?.(active.id as string, over.id as string)
      }
      return
    }

    // column drag → drop on the group zone groups by that column
    if (over.id === GROUP_DROPZONE_ID) {
      const column = table.getColumn(active.id as string)
      if (column && !column.getIsGrouped()) column.toggleGrouping()
      return
    }
    // Otherwise it's a reorder, which only applies when ordering is enabled
    // (a column may be draggable solely to support drag-to-group).
    if (!table.tableInstance.enableColumnOrdering) return
    if (active.id === over.id) return
    const base =
      table.getState().columnOrder.length > 0
        ? table.getState().columnOrder
        : table.getAllLeafColumns().map((c) => c.id)
    const oldIndex = base.indexOf(active.id as string)
    const newIndex = base.indexOf(over.id as string)
    if (oldIndex === -1 || newIndex === -1) return
    table.setColumnOrder(arrayMove(base, oldIndex, newIndex))
  }

  return { sensors, collisionDetection, handleDragEnd }
}

"use client"

import type { Row, RowData } from "@tanstack/react-table"
import { useVirtualizer } from "@tanstack/react-virtual"
import * as React from "react"

import type { DataTableInstance } from "../core/types"

export interface VirtualRowItem<TData extends RowData> {
  row: Row<TData>
  detail: boolean
}

/** Wraps a window of cells with left/right spacers when virtualizing columns. */
export type WithColumnSpacers = (
  cells: React.ReactNode[],
  keyPrefix: string
) => React.ReactNode

/**
 * Row + column virtualization for {@link DataTable}. Builds the flattened
 * virtualization list (center rows + their expanded detail panels), wires both
 * `@tanstack/react-virtual` instances, exposes them via the optional instance
 * refs, and returns the helpers the header/body/footer need to render only the
 * visible window with left/right column spacers.
 */
export function useTableVirtualizers<TData extends RowData>(
  table: DataTableInstance<TData>,
  gridRef: React.RefObject<HTMLDivElement | null>
) {
  const {
    enableRowVirtualization,
    enableColumnVirtualization,
    renderDetailPanel,
    estimateRowHeight,
    virtualOverscan,
    rowVirtualizerOptions,
    columnVirtualizerOptions,
    rowVirtualizerInstanceRef,
    columnVirtualizerInstanceRef,
  } = table.tableInstance

  // Flatten center rows (+ expanded detail panels) into a virtualization list.
  const virtualItems: VirtualRowItem<TData>[] = []
  if (enableRowVirtualization) {
    for (const row of table.getCenterRows()) {
      virtualItems.push({ row, detail: false })
      if (renderDetailPanel && row.getIsExpanded() && !row.getIsGrouped()) {
        virtualItems.push({ row, detail: true })
      }
    }
  }

  // User-supplied passthrough options, resolved from their value-or-function form.
  const rowVOptions =
    typeof rowVirtualizerOptions === "function"
      ? rowVirtualizerOptions({ table })
      : rowVirtualizerOptions
  const columnVOptions =
    typeof columnVirtualizerOptions === "function"
      ? columnVirtualizerOptions({ table })
      : columnVirtualizerOptions

  const rowVirtualizer = useVirtualizer({
    count: virtualItems.length,
    getScrollElement: () => gridRef.current,
    estimateSize: () => estimateRowHeight,
    overscan: virtualOverscan,
    measureElement:
      typeof window !== "undefined"
        ? (el) => el?.getBoundingClientRect().height ?? 0
        : undefined,
    ...rowVOptions,
  })

  // Horizontal virtualizer for wide tables. When off, count is 0 and the
  // helpers below fall through to rendering all columns.
  const leafColumns = table.getVisibleLeafColumns()
  const columnVirtualizer = useVirtualizer({
    horizontal: true,
    count: enableColumnVirtualization ? leafColumns.length : 0,
    getScrollElement: () => gridRef.current,
    estimateSize: (index) => leafColumns[index]?.getSize() ?? 150,
    overscan: virtualOverscan,
    ...columnVOptions,
  })

  // Expose the virtualizer instances for imperative control (e.g. scrollToIndex).
  React.useEffect(() => {
    if (rowVirtualizerInstanceRef)
      rowVirtualizerInstanceRef.current = rowVirtualizer
  })
  React.useEffect(() => {
    if (columnVirtualizerInstanceRef)
      columnVirtualizerInstanceRef.current = columnVirtualizer
  })

  const virtualColumns = enableColumnVirtualization
    ? columnVirtualizer.getVirtualItems()
    : []
  const colSpacerLeft = virtualColumns.length
    ? (virtualColumns[0]?.start ?? 0)
    : 0
  const colSpacerRight = virtualColumns.length
    ? columnVirtualizer.getTotalSize() -
      (virtualColumns[virtualColumns.length - 1]?.end ?? 0)
    : 0

  /** Wraps a row of cells with left/right spacers when virtualizing columns. */
  const withColumnSpacers = (
    cells: React.ReactNode[],
    keyPrefix: string
  ): React.ReactNode => {
    if (!enableColumnVirtualization) return cells
    return (
      <>
        {colSpacerLeft > 0 && (
          <td
            key={`${keyPrefix}-spacer-l`}
            aria-hidden
            style={{ width: colSpacerLeft }}
          />
        )}
        {cells}
        {colSpacerRight > 0 && (
          <td
            key={`${keyPrefix}-spacer-r`}
            aria-hidden
            style={{ width: colSpacerRight }}
          />
        )}
      </>
    )
  }

  return {
    rowVirtualizer,
    columnVirtualizer,
    virtualItems,
    virtualColumns,
    withColumnSpacers,
  }
}

"use client"

import type { ColumnDef, Row, RowData } from "@tanstack/react-table"

import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"

import type { DataTableInstance } from "../core/types"

export const ROW_ACTIONS_COLUMN_ID = "cn-row-actions"

/** Actions column: edit/save/cancel controls + the consumer's
 *  `renderRowActions` slot. When positioned `"first"` the controls align to the
 *  left edge; when `"last"` (default) they align to the right. */
export function createRowActionsColumn<TData extends RowData>(
  position: "first" | "last" = "last"
): ColumnDef<TData> {
  const align = position === "first" ? "left" : "right"
  return {
    id: ROW_ACTIONS_COLUMN_ID,
    enableSorting: false,
    enableHiding: false,
    enableColumnFilter: false,
    enableResizing: false,
    enableGrouping: false,
    size: 90,
    minSize: 80,
    meta: { disableColumnActions: true, align },
    header: () => null,
    cell: ({ row, table }) => (
      <RowActionsCell
        row={row}
        table={table as DataTableInstance<TData>}
        align={align}
      />
    ),
  }
}

function RowActionsCell<TData extends RowData>({
  row,
  table,
  align,
}: {
  row: Row<TData>
  table: DataTableInstance<TData>
  align: "left" | "right"
}) {
  const justify = align === "left" ? "justify-start" : "justify-end"
  const {
    localization,
    icons,
    enableEditing,
    editDisplayMode,
    editingRowId,
    rowDraft,
    onSaveRow,
    beginRowEdit,
    cancelEdit,
    renderRowActions,
    renderRowActionMenuItems,
  } = table.tableInstance

  const isEditingThisRow = editDisplayMode === "row" && editingRowId === row.id

  if (isEditingThisRow) {
    return (
      <div className={`flex items-center gap-1 ${justify}`}>
        <Button
          variant="ghost"
          size="icon"
          aria-label={localization.save}
          className="size-7"
          onClick={() =>
            onSaveRow?.({ row, values: rowDraft, table, exit: cancelEdit })
          }
        >
          <icons.save />
        </Button>
        <Button
          variant="ghost"
          size="icon"
          aria-label={localization.cancel}
          className="size-7"
          onClick={cancelEdit}
        >
          <icons.cancel />
        </Button>
      </div>
    )
  }

  const canInlineEdit =
    enableEditing && (editDisplayMode === "row" || editDisplayMode === "modal")

  return (
    <div className={`flex items-center gap-1 ${justify}`}>
      {canInlineEdit && (
        <Button
          variant="ghost"
          size="icon"
          aria-label={localization.edit}
          className="size-7"
          onClick={() => beginRowEdit(row)}
        >
          <icons.edit />
        </Button>
      )}
      {renderRowActions?.({ row, table })}
      {renderRowActionMenuItems && (
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button
              variant="ghost"
              size="icon"
              aria-label={localization.rowActions}
              className="size-7"
            >
              <icons.columnActions />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            {renderRowActionMenuItems({ row, table })}
          </DropdownMenuContent>
        </DropdownMenu>
      )}
    </div>
  )
}

"use client"

import type { ColumnDef, RowData } from "@tanstack/react-table"

import type { DataTableIcons } from "../core/icons"
import type { DataTableLocalization } from "../core/localization"

export const EXPAND_COLUMN_ID = "cn-expand"

/** Expand/collapse column for detail panels and tree (sub-row) expansion. */
export function createExpandColumn<TData extends RowData>(
  localization: DataTableLocalization,
  icons: DataTableIcons
): ColumnDef<TData> {
  return {
    id: EXPAND_COLUMN_ID,
    enableSorting: false,
    enableHiding: false,
    enableColumnFilter: false,
    enableResizing: false,
    size: 44,
    minSize: 44,
    meta: { disableColumnActions: true },
    header: ({ table }) =>
      table.getCanSomeRowsExpand() ? (
        <button
          type="button"
          aria-label={localization.expandAll}
          onClick={table.getToggleAllRowsExpandedHandler()}
          className="flex items-center justify-center text-muted-foreground transition-colors outline-none hover:text-foreground focus-visible:ring-2 focus-visible:ring-ring/40"
        >
          {table.getIsAllRowsExpanded() ? (
            <icons.expanded className="size-4" />
          ) : (
            <icons.collapsed className="size-4" />
          )}
        </button>
      ) : null,
    cell: ({ row }) => {
      if (!row.getCanExpand()) return null
      return (
        <button
          type="button"
          aria-label={localization.toggleRowExpanded}
          aria-expanded={row.getIsExpanded()}
          onClick={row.getToggleExpandedHandler()}
          className="flex items-center justify-center text-muted-foreground transition-colors outline-none hover:text-foreground focus-visible:ring-2 focus-visible:ring-ring/40"
        >
          {row.getIsExpanded() ? (
            <icons.expanded className="size-4" />
          ) : (
            <icons.collapsed className="size-4" />
          )}
        </button>
      )
    },
  }
}

