"use client"

import * as React from "react"
import type { ColumnDef, RowData } from "@tanstack/react-table"

import { Button } from "@/components/ui/button"

import type { DataTableIcons, IconComponent } from "../core/icons"
import type { DataTableLocalization } from "../core/localization"

export const ROW_DRAG_COLUMN_ID = "cn-row-drag"

/** dnd-kit activator props for the current row's drag handle. */
export interface RowDragHandleProps {
  attributes: Record<string, unknown>
  listeners: Record<string, unknown> | undefined
  setActivatorNodeRef: (el: HTMLElement | null) => void
}

export const RowDragContext = React.createContext<RowDragHandleProps | null>(
  null
)

/** Drag-handle column for row ordering. The handle reads dnd-kit props from
 *  {@link RowDragContext}, set by the sortable row wrapper. */
export function createRowDragHandleColumn<TData extends RowData>(
  localization: DataTableLocalization,
  icons: DataTableIcons
): ColumnDef<TData> {
  return {
    id: ROW_DRAG_COLUMN_ID,
    enableSorting: false,
    enableHiding: false,
    enableColumnFilter: false,
    enableResizing: false,
    size: 40,
    minSize: 40,
    meta: { disableColumnActions: true, align: "center" },
    header: () => null,
    cell: () => (
      <RowDragHandle label={localization.reorderRow} Icon={icons.dragHandle} />
    ),
  }
}

function RowDragHandle({
  label,
  Icon,
}: {
  label: string
  Icon: IconComponent
}) {
  const ctx = React.useContext(RowDragContext)
  return (
    <Button
      type="button"
      variant="ghost"
      size="icon"
      aria-label={label}
      ref={ctx?.setActivatorNodeRef}
      suppressHydrationWarning
      {...(ctx?.attributes ?? {})}
      {...(ctx?.listeners ?? {})}
      // touch-none: let dnd-kit's pointer sensor own the touch gesture
      // (otherwise the browser scrolls/selects text before a drag can start on
      // a phone). size-7 gives a finger-friendly tap target.
      className="size-7 cursor-grab touch-none text-muted-foreground active:cursor-grabbing"
    >
      <Icon className="size-4" />
    </Button>
  )
}

"use client"

import type { ColumnDef, RowData } from "@tanstack/react-table"

import { cn } from "@/lib/utils"

import type { DataTableIcons } from "../core/icons"
import type { DataTableLocalization } from "../core/localization"

export const ROW_NUMBER_COLUMN_ID = "cn-row-number"

/** Row-number column. `static` numbers track the current view (page-aware);
 *  `original` uses the stable source index. Optionally shows a pin toggle. */
export function createRowNumberColumn<TData extends RowData>(
  localization: DataTableLocalization,
  mode: "static" | "original",
  enableRowPinning: boolean,
  icons: DataTableIcons
): ColumnDef<TData> {
  return {
    id: ROW_NUMBER_COLUMN_ID,
    enableSorting: false,
    enableHiding: false,
    enableColumnFilter: false,
    enableResizing: false,
    size: 56,
    minSize: 48,
    meta: { disableColumnActions: true, align: "center", label: "#" },
    header: () => <span className="text-muted-foreground">#</span>,
    cell: ({ row, table }) => {
      const number =
        mode === "original"
          ? row.index + 1
          : table.getRowModel().rows.indexOf(row) +
            1 +
            table.getState().pagination.pageIndex *
              table.getState().pagination.pageSize

      if (!enableRowPinning) {
        return (
          <span className="text-xs text-muted-foreground tabular-nums">
            {number}
          </span>
        )
      }

      const pinned = row.getIsPinned()
      return (
        <span className="group/rownum relative flex items-center justify-center">
          <span
            className={cn(
              "text-xs text-muted-foreground tabular-nums",
              "group-hover/rownum:opacity-0"
            )}
          >
            {number}
          </span>
          <button
            type="button"
            aria-label={pinned ? localization.unpinRow : localization.pinRow}
            onClick={() => row.pin(pinned ? false : "top")}
            className={cn(
              "absolute inset-0 flex items-center justify-center text-muted-foreground opacity-0 transition-opacity group-hover/rownum:opacity-100 hover:text-foreground focus-visible:opacity-100",
              pinned && "text-primary opacity-100"
            )}
          >
            {pinned ? (
              <icons.pinnedRow className="size-3.5" />
            ) : (
              <icons.pin className="size-3.5" />
            )}
          </button>
        </span>
      )
    },
  }
}

"use client"

import type { ColumnDef, RowData } from "@tanstack/react-table"

import { SelectionCheckbox } from "../components/body/selection-checkbox"
import type { DataTableLocalization } from "../core/localization"

export const SELECTION_COLUMN_ID = "cn-select"

/**
 * Builds the auto-injected selection column. The header carries the
 * select-all checkbox (with indeterminate state) for multi-select tables; for
 * single-select tables the header is empty. `selectAllMode` selects the current
 * page ("page", default) or every row ("all"); `enableSelectAll: false` hides
 * the header checkbox. Clicks are isolated from row click handlers via
 * `stopPropagation`.
 */
export function createSelectionColumn<TData extends RowData>(
  localization: DataTableLocalization,
  selectAllMode: "page" | "all" = "page",
  enableSelectAll = true
): ColumnDef<TData> {
  return {
    id: SELECTION_COLUMN_ID,
    enableSorting: false,
    enableHiding: false,
    enableColumnFilter: false,
    enableResizing: false,
    size: 44,
    minSize: 44,
    meta: { disableColumnActions: true, align: "center" },
    header: ({ table }) => {
      // No select-all affordance for single-select tables or when disabled.
      if (!enableSelectAll) return null
      if (table.options.enableMultiRowSelection === false) return null
      const allMode = selectAllMode === "all"
      const allSelected = allMode
        ? table.getIsAllRowsSelected()
        : table.getIsAllPageRowsSelected()
      const someSelected = allMode
        ? table.getIsSomeRowsSelected()
        : table.getIsSomePageRowsSelected()
      return (
        <div
          className="flex items-center justify-center"
          onClick={(e) => e.stopPropagation()}
        >
          <SelectionCheckbox
            aria-label={localization.selectAll}
            checked={allSelected}
            indeterminate={someSelected && !allSelected}
            onCheckedChange={(value) =>
              allMode
                ? table.toggleAllRowsSelected(!!value)
                : table.toggleAllPageRowsSelected(!!value)
            }
          />
        </div>
      )
    },
    cell: ({ row }) => (
      <div
        className="flex items-center justify-center"
        onClick={(e) => e.stopPropagation()}
      >
        <SelectionCheckbox
          aria-label={localization.selectRow}
          checked={row.getIsSelected()}
          disabled={!row.getCanSelect()}
          onCheckedChange={(value) => row.toggleSelected(!!value)}
        />
      </div>
    ),
  }
}

import type { Column, RowData, Table } from "@tanstack/react-table"
import type { CSSProperties } from "react"

import type { DataTableInstance } from "../core/types"

/**
 * Sticky positioning for a pinned column. Offsets come from TanStack
 * (`getStart`/`getAfter`) so multiple pinned columns stack correctly.
 */
export function getColumnPinningStyle<TData extends RowData, TValue>(
  column: Column<TData, TValue>
): CSSProperties {
  const pinned = column.getIsPinned()
  if (!pinned) return {}
  return {
    position: "sticky",
    zIndex: 2,
    ...(pinned === "left"
      ? { left: column.getStart("left") }
      : { right: column.getAfter("right") }),
  }
}

/**
 * Edge-shadow class for the boundary pinned columns (last left / first right),
 * built from `--border` (via a utility) so it reads in light and dark.
 */
export function getColumnPinningClass<TData extends RowData, TValue>(
  column: Column<TData, TValue>
): string {
  const pinned = column.getIsPinned()
  if (!pinned) return ""
  const isLastLeft = pinned === "left" && column.getIsLastColumn("left")
  const isFirstRight = pinned === "right" && column.getIsFirstColumn("right")
  if (isLastLeft) {
    return "after:pointer-events-none after:absolute after:inset-y-0 after:-right-px after:w-2 after:translate-x-full after:bg-gradient-to-r after:from-border/60 after:to-transparent"
  }
  if (isFirstRight) {
    return "before:pointer-events-none before:absolute before:inset-y-0 before:-left-px before:w-2 before:-translate-x-full before:bg-gradient-to-l before:from-border/60 before:to-transparent"
  }
  return ""
}

/**
 * CSS custom properties holding each column's size, set once on the table
 * element. Cells read them via `width: calc(var(--col-…-size) * 1px)` so a
 * resize drag updates a variable instead of re-rendering every cell.
 */
export function getColumnSizeVars<TData extends RowData>(
  table: Table<TData>
): Record<string, string> {
  const headers = table.getFlatHeaders()
  const vars: Record<string, string> = {}
  for (const header of headers) {
    vars[`--header-${header.id}-size`] = `${header.getSize()}`
    vars[`--col-${header.column.id}-size`] = `${header.column.getSize()}`
  }
  return vars
}

export function getColumnWidthStyle(columnId: string): CSSProperties {
  return { width: `calc(var(--col-${columnId}-size) * 1px)` }
}

/**
 * Resolves a column's width style. While resizing, widths come from CSS vars.
 * Otherwise honor an explicitly defined `columnDef.size` (MRT behaviour) but
 * leave unsized columns to the browser's auto layout so the table still fills
 * its container. Column virtualization needs every column to have a concrete
 * width.
 */
export function getWidthStyle<TData extends RowData>(
  column: Column<TData, unknown>,
  table: DataTableInstance<TData>
): CSSProperties {
  const { enableColumnResizing, enableColumnVirtualization } =
    table.tableInstance
  if (enableColumnResizing) return getColumnWidthStyle(column.id)
  if (enableColumnVirtualization || column.columnDef.size != null) {
    const size = column.getSize()
    return { width: size, minWidth: size }
  }
  return {}
}

